    ('cnpreqin-3fcc3c660d5a7a4d', 0, '靈臺', NULL, NULL, NULL, '經始靈臺，經之營之。庶民攻之，不日成之。
經始勿亟，庶民子來。王在靈囿，麀鹿攸伏。
麀鹿濯濯，白鳥翯翯。王在靈沼，於牣魚躍。
虡業維樅，賁鼓維鏞。於論鼓鍾，於樂辟廱。
於論鼓鍾，於樂辟廱。鼉鼓逢逢，矇瞍奏公。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00321","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-34-38-2d-9748-81fa-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-9748-81fa","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-34-38-2d-9748-81fa-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-9748-81fa"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%9D%88%E8%87%BA","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '下武', NULL, NULL, NULL, '下武維周，世有哲王。三後在天，王配于京。
王配于京，世德作求。永言配命，成王之孚。
成王之孚，下土之式。永言孝思，孝思維則。
媚茲一人，應侯順德。永言孝思，昭哉嗣服。
昭茲來許，繩其祖武。於萬斯年，受天之祜。
受天之祜，四方來賀。於萬斯年，不遐有佐。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00322","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-34-39-2d-4e0b-6b66-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-4e0b-6b66","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-34-39-2d-4e0b-6b66-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-4e0b-6b66"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E4%B8%8B%E6%AD%A6","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '文王有聲', NULL, NULL, NULL, '文王有聲，遹駿有聲。遹求厥寧，遹觀厥成。文王烝哉。
文王受命，有此武功。既伐于崇，作邑于豐。文王烝哉。
築城伊淢，作豐伊匹。匪棘其欲，遹追來孝。王後烝哉。
王公伊濯，維豐之垣。四方攸同，王後維翰。王後烝哉。
豐水東注，維禹之績。四方攸同，皇王維辟。皇王烝哉。
鎬京辟廱，自西自東。自南自北，無思不服。皇王烝哉。
考卜維王，宅是鎬京。維龜正之，武王成之。武王烝哉。
豐水有芑，武王豈不仕。詒厥孫謀，以燕翼子。武王烝哉。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00323","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-30-2d-6587-738b-6709-8072-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6587-738b-6709-8072","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-30-2d-6587-738b-6709-8072-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6587-738b-6709-8072"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%96%87%E7%8E%8B%E6%9C%89%E8%81%B2","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '生民', NULL, NULL, NULL, '厥初生民，時維姜嫄。生民如何？克禋克祀，以弗無子。
履帝武敏歆，攸介攸止。載震載夙，載生載育。時維後稷。
誕彌厥月，先生如達。不坼不副，無菑無害。
以赫厥靈，上帝不寧。不康禋祀，居然生子。
誕寘之隘巷，牛羊腓字之。誕寘之平林，會伐平林。
誕寘之寒冰，鳥覆翼之。鳥乃去矣，後稷呱矣。
實覃實訏，厥聲載路。誕實匍匐，克岐克嶷，以就口食。
蓺之荏菽，荏菽斾斾，禾役穟穟。麻麥幪幪，瓜瓞唪唪。
誕後稷之穡，有相之道。茀厥豐草，種之黃茂。
實方實苞，實種實褎，實發實秀，實堅實好，實穎實栗。即有邰家室。
誕降嘉種，維秬維秠，維穈維芑。
恒之秬秠，是穫是畝。恒之穈芑，是任是負。以歸肇祀。
誕我祀如何？或舂或揄，或簸或蹂。釋之叟叟，烝之浮浮。
載謀載惟，取蕭祭脂，取羝以軷。載燔載烈，以興嗣歲。
卬盛于豆，于豆于登。其香始升，上帝居歆。
胡臭亶時？後稷肇祀，庶無罪悔，以迄于今。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00324","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-31-2d-751f-6c11-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-751f-6c11","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-31-2d-751f-6c11-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-751f-6c11"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%94%9F%E6%B0%91","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '行葦', NULL, NULL, NULL, '敦彼行葦，牛羊勿踐履。方苞方體，維葉泥泥。
戚戚兄弟，莫遠具爾。或肆之筵，或授之几。
肆筵設席，授几有緝御。或獻或酢，洗爵奠斝。
醓醢以薦，或燔或炙。嘉殽脾臄，或歌或咢。
敦弓既堅，四鍭既鈞。舍矢既均，序賓以賢。
敦弓既句，既挾四鍭。四鍭如樹，序賓以不侮。
曾孫維主，酒醴維醹。酌以大鬥，以祈黃耇。
黃耇台背，以引以翼，壽考維祺，以介景福。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00325","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-32-2d-884c-8466-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-884c-8466","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-32-2d-884c-8466-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-884c-8466"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%A1%8C%E8%91%A6","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '既醉', NULL, NULL, NULL, '既醉以酒，既飽以德。君子萬年，介爾景福。
既醉以酒，爾殽既將。君子萬年，介爾昭明。
昭明有融，高朗令終。令終有俶，公尸嘉告。
其告維何？籩豆靜嘉。朋友攸攝，攝以威儀。
威儀孔時，君子有孝子。孝子不匱，永錫爾類。
其類維何？室家之壼。君子萬年，永錫祚胤。
其胤維何？天被爾祿。君子萬年，景命有僕。
其僕維何？釐爾女士。釐爾女士，從以孫子。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00326","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-33-2d-65e2-9189-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-65e2-9189","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-33-2d-65e2-9189-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-65e2-9189"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%97%A2%E9%86%89","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '鳬鷖', NULL, NULL, NULL, '鳧鷖在涇，公尸來燕來寧。爾酒既清，爾殽既馨。公尸燕飲，福祿來成。
鳧鷖在沙，公尸來燕來宜。爾酒既多，爾殽既嘉。公尸燕飲，福祿來為。
鳧鷖在渚，公尸來燕來處。爾酒既湑，爾殽伊脯。公尸燕飲，福祿來下。
鳧鷖在潀，公尸來燕來宗。既燕于宗，福祿攸降。公尸燕飲，福祿來崇。
鳧鷖在亹，公尸來止熏熏。旨酒欣欣，燔炙芬芬。公尸燕飲，無有後艱。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00327","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-34-2d-9cec-9dd6-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-9cec-9dd6","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-34-2d-9cec-9dd6-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-9cec-9dd6"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%B3%AC%E9%B7%96","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '假樂', NULL, NULL, NULL, '假樂君子，顯顯令德。宜民宜人，受祿于天。保右命之，自天申之。
乾祿百福，子孫千億。穆穆皇皇，宜君宜王。不愆不忘，率由舊章。
威儀抑抑，德音秩秩。無怨無惡，率由羣匹。受福無疆，四方之綱。
之綱之紀，燕及朋友。百辟卿士，媚于天子。不解于位，民之攸塈。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00328","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-35-2d-5047-6a02-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5047-6a02","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-35-2d-5047-6a02-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5047-6a02"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%81%87%E6%A8%82","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '公劉', NULL, NULL, NULL, '篤公劉，匪居匪康，迺埸迺疆。迺積迺倉，迺裹餱糧。
于橐于囊，思輯用光。弓矢斯張，乾戈戚揚，爰方啟行。
篤公劉，于胥斯原，既庶既繁，既順迺宣，而無永歎。
陟則在巘，復降在原。何以舟之？維玉及瑤，鞞琫容刀。
篤公劉，逝彼百泉，瞻彼溥原，迺陟南岡，乃覯于京。
京師之野，于時處處。于時廬旅，于時言言，于時語語。
篤公劉，于京斯依，蹌蹌濟濟，俾筵俾几。既登乃依。
乃造其曹，執豕于牢，酌之用匏。食之飲之，君之宗之。
篤公劉，既溥既長，既景迺岡，相其陰陽，觀其流泉。
其軍三單，度其隰原，徹田為糧。度其夕陽，豳居允荒。
篤公劉，于豳斯館，涉渭為亂，取厲取鍛，止基迺理。
爰眾爰有，夾其皇澗。遡其過澗，止旅乃密，芮鞫之即。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00329","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-36-2d-516c-5289-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-516c-5289","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-36-2d-516c-5289-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-516c-5289"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%85%AC%E5%8A%89","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '泂酌', NULL, NULL, NULL, '泂酌彼行潦，挹彼注茲，可以餴饎。豈弟君子，民之父母。
泂酌彼行潦，挹彼注茲，可以濯罍。豈弟君子，民之攸歸。
泂酌彼行潦，挹彼注茲，可以濯溉。豈弟君子，民之攸塈。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00330","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-37-2d-6cc2-914c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6cc2-914c","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-37-2d-6cc2-914c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6cc2-914c"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%B3%82%E9%85%8C","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '卷阿', NULL, NULL, NULL, '有卷者阿，飄風自南。豈弟君子，來遊來歌，以矢其音。
伴奐爾遊矣，優遊爾休矣。豈弟君子，俾爾彌爾性，似先公酋矣。
爾土宇昄章，亦孔之厚矣。豈弟君子，俾爾彌爾性，百神爾主矣。
爾受命長矣，茀祿爾康矣。豈弟君子，俾爾彌爾性，純嘏爾常矣。
有馮有翼，有孝有德，以引以翼。豈弟君子，四方為則。
顒顒卬卬，如圭如璋，令聞令望。豈弟君子，四方為綱。
鳳皇于飛，翽翽其羽，亦集爰止。藹藹王多吉士，維君子使，媚于天子。
鳳皇于飛，翽翽其羽，亦傅于天。藹藹王多吉人，維君子命，媚于庶人。
鳳皇鳴矣，于彼高岡。梧桐生矣，于彼朝陽。菶菶萋萋，雝雝喈喈。
君子之車，既庶且多。君子之馬，既閑且馳。矢詩不多，維以遂歌。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00331","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-38-2d-5377-963f-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5377-963f","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-38-2d-5377-963f-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5377-963f"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%8D%B7%E9%98%BF","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '民勞', NULL, NULL, NULL, '民亦勞止，汔可小康。惠此中國，以綏四方。
無縱詭隨，以謹無良。式遏寇虐，憯不畏明。柔遠能邇，以定我王。
民亦勞止，汔可小休。惠此中國，以為民逑。
無縱詭隨，以謹惛怓。式遏寇虐，無俾民憂。無棄爾勞，以為王休。
民亦勞止，汔可小息。惠此京師，以綏四國。
無縱詭隨，以謹罔極。式遏寇虐，無俾作慝。敬慎威儀，以近有德。
民亦勞止，汔可小愒。惠此中國，俾民憂泄。
無縱詭隨，以謹醜厲。式遏寇虐，無俾正敗。戎雖小子，而式弘大。
民亦勞止，汔可小安。惠此中國，國無有殘。
無縱詭隨，以謹繾綣。式遏寇虐，無俾正反。王欲玉女，是用大諫。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00332","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-39-2d-6c11-52de-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6c11-52de","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-35-39-2d-6c11-52de-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6c11-52de"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%B0%91%E5%8B%9E","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '板', NULL, NULL, NULL, '上帝板板，下民卒癉。出話不然，為猶不遠。
靡聖管管，不實於亶。猶之未遠，是用大諫。
天之方難，無然憲憲。天之方蹶，無然泄泄。
辭之輯矣，民之洽矣。辭之懌矣，民之莫矣。
我雖異事，及爾同寮。我即爾謀，聽我嚻嚻。
我言維服，勿以為笑。先民有言，詢于芻蕘。
天之方虐，無然謔謔。老夫灌灌，小子蹻蹻。
匪我言耄，爾用憂謔。多將熇熇，不可救藥。
天之方懠，無為夸毗。威儀卒迷，善人載尸。
民之方殿屎，則莫我敢葵。喪亂蔑資，曾莫惠我師。
天之牖民，如壎如篪。如璋如圭，如取如攜。
攜無曰益，牖民孔易。民之多辟，無自立辟。
价人維藩，大師維垣。大邦維屏，大宗維翰。
懷德維寧，宗子維城。無俾城壞，無獨斯畏。
敬天之怒，無敢戲豫。敬天之渝，無敢馳驅。
昊天曰明，及爾出王。昊天曰旦，及爾遊衍。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00333","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-30-2d-677f-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-677f","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-30-2d-677f-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-677f"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%9D%BF","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '蕩', NULL, NULL, NULL, '蕩蕩上帝，下民之辟。疾威上帝，其命多辟。
天生烝民，其命匪諶。靡不有初，鮮克有終。
文王曰咨！咨女殷商，曾是彊禦，曾是掊克。
曾是在位，曾是在服。天降滔德，女興是力。
文王曰咨！咨女殷商，而秉義類，彊禦多懟。
流言以對，寇攘式內。侯作侯祝，靡屆靡究。
文王曰咨！咨女殷商，女炰烋于中國，斂怨以為德。
不明爾德，時無背無側。爾德不明，以無陪無卿。
文王曰咨！咨女殷商，天不湎爾以酒，不義從式。
既愆爾止，靡明靡晦；式號式呼，俾晝作夜。
文王曰咨！咨女殷商，如蜩如螗，如沸如羹。
小大近喪，人尚乎由行。內奰于中國，覃及鬼方。
文王曰咨！咨女殷商，匪上帝不時，殷不用舊。
雖無老成人，尚有典刑。曾是莫聽，大命以傾。
文王曰咨！咨女殷商，人亦有言，顛沛之揭。
枝葉未有害，本實先撥。殷鑒不遠，在夏後之世。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00334","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-31-2d-8569-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8569","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-31-2d-8569-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8569"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%95%A9","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '抑', NULL, NULL, NULL, '抑抑威儀，維德之隅。人亦有言，靡哲不愚。
庶人之愚，亦職維疾。哲人之愚，亦維斯戾。
無競維人，四方其訓之。有覺德行，四國順之。
訏謨定命，遠猶辰告。敬慎威儀，維民之則。
其在于今，興迷亂于政。顛覆厥德，荒湛于酒。
女雖湛樂從，弗念厥紹；罔敷求先王，克共明刑。
肆皇天弗尚，如彼泉流，無淪胥以亡。
夙興夜寐，洒埽庭內，維民之章。
脩爾車馬，弓矢戎兵，用戒戎作，用逷蠻方。
質爾人民，謹爾侯度，用戒不虞。
慎爾出話，敬爾威儀，無不柔嘉。
白圭之玷，尚可磨也。斯言之玷，不可為也。
無易由言，無曰苟矣。莫捫朕舌，言不可逝矣。
無言不讎，無德不報。惠于朋友，庶民小子。
子孫繩繩，萬民靡不承。
視爾友君子，輯柔爾顏，不遐有愆。
相在爾室，尚不愧于屋漏。無曰不顯，莫予雲覯。
神之格思，不可度思，矧可射思。
辟爾為德，俾臧俾嘉。淑慎爾止，不愆于儀。
不僭不賊，鮮不為則。
投我以桃，報之以李。彼童而角，實虹小子。
荏染柔木，言緡之絲。溫溫恭人，維德之基。
其維哲人，告之話言，順德之行。
其維愚人，覆謂我僭，民各有心。
於乎小子，未知臧否。
匪手攜之，言示之事。匪面命之，言提其耳。
借曰未知，亦既抱子。民之靡盈，誰夙知而莫成。
昊天孔昭，我生靡樂。視爾夢夢，我心慘慘。
誨爾諄諄，聽我藐藐，匪用為教，覆用為虐。
借曰未知，亦聿既耄。
於乎小子，告爾舊止。
聽用我謀，庶無大悔。天方艱難，曰喪厥國。
取譬不遠，昊天不忒。回遹其德，俾民大棘。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00335","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-32-2d-6291-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6291","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-32-2d-6291-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6291"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%8A%91","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '桑柔', NULL, NULL, NULL, '菀彼桑柔，其下侯旬。捋采其劉，瘼此下民。
不殄心憂，倉兄填兮。倬彼昊天，寧不我矜。
四牡騤騤，旟旐有翩。亂生不夷，靡國不泯。
民靡有黎，具禍以燼。於乎有哀，國步斯頻。
國步蔑資，天不我將。靡所止疑，雲徂何往？
君子實維，秉心無競。誰生厲階？至今為梗。
憂心慇慇，念我土宇。我生不辰，逢天僤怒。
自西徂東，靡所定處。多我覯痻，孔棘我圉。
為謀為毖，亂況斯削，告爾憂恤，誨爾序爵。
誰能執熱，逝不以濯，其何能淑，載胥及溺。
如彼遡風，亦孔之僾。民有肅心，荓雲不逮。
好是稼穡，力民代食，稼穡維寶，代食維好。
天降喪亂，滅我立王。降此蟊賊，稼穡卒痒。
哀恫中國，具贅卒荒。靡有旅力，以念穹蒼。
維此惠君，民人所瞻。秉心宣猶，考慎其相。
維彼不順，自獨俾臧，自有肺腸，俾民卒狂。
瞻彼中林，甡甡其鹿。朋友已譖，不胥以穀。
人亦有言：進退維谷。
維此聖人，瞻言百里。維彼愚人，覆狂以喜。
匪言不能，胡斯畏忌。
維此良人，弗求弗迪，維彼忍心，是顧是復。
民之貪亂，寧為荼毒。
大風有隧，有空大谷，維此良人，作為式穀。
維彼不順，征以中垢。
大風有隧，貪人敗類，聽言則對，誦言如醉。
匪用其良，覆俾我悖。
嗟爾朋友！予豈不知而作？。
如彼飛蟲，時亦弋獲。既之陰女，反予來赫。
民之罔極，職涼善背。為民不利，如雲不克。
民之回遹，職競用力。
民之未戾，職盜為寇。涼曰不可！
覆背善詈，雖曰匪予，既作爾歌！', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00336","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-33-2d-6851-67d4-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6851-67d4","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-33-2d-6851-67d4-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6851-67d4"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%A1%91%E6%9F%94","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '雲漢', NULL, NULL, NULL, '倬彼雲漢，昭回于天。王曰於乎，何辜今之人？天降喪亂，饑饉薦臻。
靡神不舉，靡愛斯牲。圭璧既卒，寧莫我聽。
旱既大甚，蘊隆蟲蟲。不殄禋祀，自郊徂宮。上下奠瘞，靡神不宗。
後稷不克，上帝不臨。耗斁下土，寧丁我躬。
旱既大甚，則不可推。兢兢業業，如霆如雷。周餘黎民，靡有孑遺。
昊天上帝，則不我遺。胡不相畏？先祖于摧。
旱既大甚，則不可沮。赫赫炎炎，雲我無所。大命近止，靡瞻靡顧。
羣公先正，則不我助。父母先祖，胡寧忍予？
旱既大甚，滌滌山川。旱魃為虐，如惔如焚。我心憚暑，憂心如薰。
羣公先正，則不我聞。昊天上帝，寧俾我遯？
旱既大甚，黽勉畏去。胡寧瘨我以旱？憯不知其故。祈年孔夙，方社不莫。
昊天上帝，則不我虞。敬恭明神，宜無悔怒。
旱既大甚，散無友紀。鞫哉庶正，疚哉冢宰。趣馬師氏，膳夫左右。
靡人不周，無不能止。瞻卬昊天，雲如何里？
瞻卬昊天，有嘒其星。大夫君子，昭假無贏。大命近止，無棄爾成。
何求為我？以戾庶正。瞻卬昊天，曷惠其寧？', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00337","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-34-2d-96f2-6f22-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-96f2-6f22","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-34-2d-96f2-6f22-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-96f2-6f22"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%9B%B2%E6%BC%A2","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '崧高', NULL, NULL, NULL, '崧高維嶽，駿極于天。維嶽降神，生甫及申。
維申及甫，維周之翰。四國于蕃，四方于宣。
亹亹申伯，王纘之事。于邑于謝，南國是式。
王命召伯，定申伯之宅。登是南邦，世執其功。
王命申伯，式是南邦。因是謝人，以作爾庸。
王命召伯，徹申伯土田。王命傅御，遷其私人。
申伯之功，召伯是營。有俶其城，寢廟既成。
既成藐藐，王錫申伯。四牡蹻蹻，鉤膺濯濯。
王遣申伯，路車乘馬。我圖爾居，莫如南土。
錫爾介圭，以作爾寶。往近王舅，南土是保。
申伯信邁，王餞于郿。申伯還南，謝于誠歸。
王命召伯，徹申伯土疆。以峙其粻，式遄其行。
申伯番番，既入于謝，徒御嘽嘽。
周邦咸喜，戎有良翰。不顯申伯，王之元舅，文武是憲。
申伯之德，柔惠且直。揉此萬邦，聞于四國。
吉甫作誦，其詩孔碩。其風肆好，以贈申伯。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00338","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-35-2d-5d27-9ad8-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5d27-9ad8","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-35-2d-5d27-9ad8-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5d27-9ad8"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%B4%A7%E9%AB%98","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '烝民', NULL, NULL, NULL, '天生烝民，有物有則。民之秉彝，好是懿德。
天監有周，昭假于下。保茲天子，生仲山甫。
仲山甫之德，柔嘉維則。令儀令色，小心翼翼。
古訓是式，威儀是力。天子是若，明命使賦。
王命仲山甫，式是百辟。纘戎祖考，王躬是保。
出納王命，王之喉舌。賦政于外，四方爰發。
肅肅王命，仲山甫將之。邦國若否，仲山甫明之。
既明且哲，以保其身。夙夜匪解，以事一人。
人亦有言：柔則茹之，剛則吐之。
維仲山甫，柔亦不茹，剛亦不吐；不侮矜寡，不畏彊禦。
人亦有言：德輶如毛，民鮮克舉之。
我儀圖之，維仲山甫舉之。愛莫助之。袞職有闕，維仲山甫補之。
仲山甫出祖，四牡業業，征夫捷捷。
每懷靡及，四牡彭彭，八鸞鏘鏘。王命仲山甫，城彼東方。
四牡騤騤，八鸞喈喈。仲山甫徂齊，式遄其歸。
吉甫作誦，穆如清風。仲山甫永懷，以慰其心。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00339","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-36-2d-70dd-6c11-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-70dd-6c11","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-36-2d-70dd-6c11-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-70dd-6c11"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%83%9D%E6%B0%91","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '韓奕', NULL, NULL, NULL, '奕奕梁山，維禹甸之。有倬其道，韓侯受命。
王親命之，纘戎祖考，無廢朕命，夙夜匪解，虔共爾位。
朕命不易，榦不庭方，以佐戎辟。
四牡奕奕，孔脩且張。韓侯入覲，以其介圭，入覲于王。
王錫韓侯，淑旂綏章。簟茀錯衡，玄袞赤舄。
鉤膺鏤鍚，鞹鞃淺幭，鞗革金厄。
韓侯出祖，出宿于屠。顯父餞之，清酒百壺。
其殽維何？炰鼈鮮魚。其蔌維何？維筍及蒲。
其贈維何？乘馬路車。籩豆有且，侯氏燕胥。
韓侯取妻，汾王之甥，蹶父之子。
韓侯迎止，于蹶之里。百兩彭彭，八鸞鏘鏘，不顯其光。
諸娣從之，祁祁如雲。韓侯顧之，爛其盈門。
蹶父孔武，靡國不到。為韓姞相攸，莫如韓樂。
孔樂韓土，川澤訏訏。魴鱮甫甫，麀鹿噳噳。
有熊有羆，有貓有虎。慶既令居，韓姞燕譽。
溥彼韓城，燕師所完。以先祖受命，因時百蠻。
王錫韓侯，其追其貊。奄受北國，因以其伯。
實墉實壑，實畝實籍。獻其貔皮，赤豹黃羆。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00340","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-37-2d-97d3-5955-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-97d3-5955","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-37-2d-97d3-5955-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-97d3-5955"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%9F%93%E5%A5%95","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '江漢', NULL, NULL, NULL, '江漢浮浮，武夫滔滔。匪安匪遊，淮夷來求。
既出我車，既設我旟，匪安匪舒，淮夷來鋪。
江漢湯湯，武夫洸洸。經營四方，告成于王。
四方既平，王國庶定。時靡有爭，王心載寧。
江漢之滸，王命召虎。式辟四方，徹我疆土。
匪疚匪棘，王國來極。于疆于理，至于南海。
王命召虎，來旬來宣。文武受命，召公維翰。
無曰予小子，召公是似。肇敏戎公，用錫爾祉。
釐爾圭瓚，秬鬯一卣，告于文人。
錫山土田，于周受命，自召祖命。
虎拜稽首，天子萬年。
虎拜稽首，對揚王休。作召公考，天子萬壽。
明明天子，令聞不已。矢其文德，洽此四國。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00341","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-38-2d-6c5f-6f22-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6c5f-6f22","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-38-2d-6c5f-6f22-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6c5f-6f22"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%B1%9F%E6%BC%A2","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '常武', NULL, NULL, NULL, '赫赫明明，王命卿士。南仲大祖，大師皇父，
整我六師，以脩我戎。既敬既戒，惠此南國。
王謂尹氏，命程伯休父，左右陳行，戒我師旅。
率彼淮浦，省此徐土。不留不處，三事就緒。
赫赫業業，有嚴天子。王舒保作，匪紹匪遊。
徐方繹騷，震驚徐方。如雷如霆，徐方震驚。
王奮厥武，如震如怒。進厥虎臣，闞如虓虎。
鋪敦淮濆，仍執醜虜。截彼淮浦，王師之所。
王旅嘽嘽，如飛如翰，如江如漢。如山之苞，如川之流。
緜緜翼翼，不測不克，濯征徐國。
王猶允塞，徐方既來。徐方既同，天子之功。
四方既平，徐方來庭。徐方不回，王曰還歸。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00342","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-39-2d-5e38-6b66-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5e38-6b66","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-36-39-2d-5e38-6b66-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5e38-6b66"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%B8%B8%E6%AD%A6","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '瞻卬', NULL, NULL, NULL, '瞻卬昊天，則不我惠。孔填不寧，降此大厲。
邦靡有定，士民其瘵。
蟊賊蟊疾，靡有夷屆。罪罟不收，靡有夷瘳。
人有土田，女反有之；人有民人，女覆奪之。
此宜無罪，女反收之；彼宜有罪，女覆說之。
哲夫成城，哲婦傾城。
懿厥哲婦，為梟為鴟。婦有長舌，維厲之階。
亂匪降自天，生自婦人。匪教匪誨，時維婦寺。
鞫人忮忒，譖始竟背。豈曰不極？伊胡為慝！
如賈三倍，君子是識。婦無公事，休其蠶織。
天何以刺？何神不富？舍爾介狄，維予胥忌。
不弔不祥，威儀不類。人之雲亡，邦國殄瘁。
天之降罔，維其優矣。人之雲亡，心之憂矣。
天之降罔，維其幾矣。人之雲亡，心之悲矣。
觱沸檻泉，維其深矣。心之憂矣，寧自今矣。
不自我先，不自我後。藐藐昊天，無不克鞏。
無忝皇祖，式救爾後。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00343","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-30-2d-77bb-536c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-77bb-536c","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-30-2d-77bb-536c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-77bb-536c"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%9E%BB%E5%8D%AC","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '召旻', NULL, NULL, NULL, '旻天疾威，天篤降喪。
瘨我饑饉，民卒流亡。我居圉卒荒。
天降罪罟，蟊賊內訌。
昏椓靡共，潰潰回遹。實靖夷我邦。
皐皐訿訿，曾不知其玷。
兢兢業業，孔填不寧。我位孔貶。
如彼歲旱，草不潰茂。
如彼棲苴。我相此邦，無不潰止。
維昔之富，不如時？維今之疚，不如茲？
彼疏斯粺，胡不自替？職兄斯引。
池之竭矣，不雲自頻？泉之竭矣，不雲自中？
溥斯害矣，職兄斯弘，不烖我躬？
昔先王受命，有如召公，日辟國百里，今也日蹙國百里。
於乎哀哉，維今之人，不尚有舊。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00344","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-31-2d-53ec-65fb-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-53ec-65fb","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-31-2d-53ec-65fb-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-53ec-65fb"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%8F%AC%E6%97%BB","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '清廟', NULL, NULL, NULL, '於穆清廟，肅雝顯相。
濟濟多士，秉文之德。
對越在天，駿奔走在廟。
不顯不承，無射於人斯。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00345","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-32-2d-6e05-5edf-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6e05-5edf","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-32-2d-6e05-5edf-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6e05-5edf"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%B8%85%E5%BB%9F","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '維天之命', NULL, NULL, NULL, '維天之命，於穆不已。
於乎不顯，文王之德之純。
假以溢我，我其收之。
駿惠我文王，曾孫篤之。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00346","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-33-2d-7dad-5929-4e4b-547d-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7dad-5929-4e4b-547d","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-33-2d-7dad-5929-4e4b-547d-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7dad-5929-4e4b-547d"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%B6%AD%E5%A4%A9%E4%B9%8B%E5%91%BD","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '維清', NULL, NULL, NULL, '維清緝熙，文王之典。
肇禋。迄用有成，維周之禎。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00347","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-34-2d-7dad-6e05-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7dad-6e05","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-34-2d-7dad-6e05-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7dad-6e05"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%B6%AD%E6%B8%85","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '烈文', NULL, NULL, NULL, '烈文辟公，錫茲祉福。惠我無疆，子孫保之。
無封靡于爾邦，維王其崇之。念茲戎功，繼序其皇之。
無競維人，四方其訓之。不顯維德，百辟其刑之。
於乎前王不忘。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00348","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-35-2d-70c8-6587-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-70c8-6587","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-35-2d-70c8-6587-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-70c8-6587"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%83%88%E6%96%87","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '天作', NULL, NULL, NULL, '天作高山，大王荒之。
彼作矣，文王康之。
彼徂矣，岐有夷之行。
子孫保之。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00349","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-36-2d-5929-4f5c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5929-4f5c","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-36-2d-5929-4f5c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5929-4f5c"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%A4%A9%E4%BD%9C","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '昊天有成命', NULL, NULL, NULL, '昊天有成命，二後受之。
成王不敢康，夙夜基命宥密。
於緝熙！單厥心。肆其靖之。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00350","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-37-2d-660a-5929-6709-6210-547d-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-660a-5929-6709-6210-547d","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-37-2d-660a-5929-6709-6210-547d-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-660a-5929-6709-6210-547d"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%98%8A%E5%A4%A9%E6%9C%89%E6%88%90%E5%91%BD","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '我將', NULL, NULL, NULL, '我將我享，維羊維牛，維天其右之。
儀式刑文王之典，日靖四方。
伊嘏文王，既右饗之。
我其夙夜，畏天之威，于時保之。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00351","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-38-2d-6211-5c07-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6211-5c07","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-38-2d-6211-5c07-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6211-5c07"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%88%91%E5%B0%87","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '時邁', NULL, NULL, NULL, '時邁其邦，昊天其子之。
實右序有周，薄言震之，莫不震疊。
懷柔百神，及河喬嶽。允王維後。
明昭有周，式序在位。
載戢乾戈，載櫜弓矢。
我求懿德，肆于時夏。
允王保之。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00352","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-39-2d-6642-9081-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6642-9081","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-37-39-2d-6642-9081-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6642-9081"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%99%82%E9%82%81","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '執競', NULL, NULL, NULL, '執競武王，無競維烈，不顯成康，上帝是皇。自彼成康，奄有四方。
斤斤其明！鐘鼓喤喤，磬筦將將，降福穰穰，降福簡簡，威儀反反。
既醉既飽，福祿來反。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00353","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-30-2d-57f7-7af6-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-57f7-7af6","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-30-2d-57f7-7af6-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-57f7-7af6"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%9F%B7%E7%AB%B6","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '思文', NULL, NULL, NULL, '思文後稷，克配彼天。立我烝民，莫匪爾極。
貽我來牟，帝命率育，無此疆爾界，陳常于時夏。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00354","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-31-2d-601d-6587-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-601d-6587","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-31-2d-601d-6587-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-601d-6587"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%80%9D%E6%96%87","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '臣工', NULL, NULL, NULL, '嗟嗟臣工，敬爾在公。王釐爾成，來咨來茹。
嗟嗟保介，維莫之春，亦又何求？如何新畬？
於皇來牟，將受厥明。明昭上帝，迄用康年。
命我衆人，庤乃錢鎛。奄觀銍艾。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00355","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-32-2d-81e3-5de5-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-81e3-5de5","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-32-2d-81e3-5de5-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-81e3-5de5"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%87%A3%E5%B7%A5","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '噫嘻', NULL, NULL, NULL, '噫嘻成王，既昭假爾，率時農夫，播厥百穀。
駿發爾私，終三十里，亦服爾耕，十千維耦。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00356","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-33-2d-566b-563b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-566b-563b","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-33-2d-566b-563b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-566b-563b"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%99%AB%E5%98%BB","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '振鷺', NULL, NULL, NULL, '振鷺于飛，于彼西雝。我客戾止，亦有斯容。
在彼無惡，在此無斁。庶幾夙夜，以永終譽。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00357","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-34-2d-632f-9dfa-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-632f-9dfa","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-34-2d-632f-9dfa-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-632f-9dfa"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%8C%AF%E9%B7%BA","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '豐年', NULL, NULL, NULL, '豐年多黍多稌，亦有高廩，萬億及秭。
為酒為醴，烝畀祖妣，以洽百禮，降福孔皆。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00358","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-35-2d-8c50-5e74-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8c50-5e74","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-35-2d-8c50-5e74-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8c50-5e74"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%B1%90%E5%B9%B4","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '有瞽', NULL, NULL, NULL, '有瞽有瞽，在周之庭。設業設虡，崇牙樹羽。應田縣鼓，鞉磬柷圉。
既備乃奏，簫管備舉。喤喤厥聲，肅雝和鳴，先祖是聽。
我客戾止，永觀厥成。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00359","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-36-2d-6709-77bd-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6709-77bd","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-36-2d-6709-77bd-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6709-77bd"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%9C%89%E7%9E%BD","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '潛', NULL, NULL, NULL, '猗與漆沮，潛有多魚。
有鱣有鮪，鰷鱨鰋鯉。
以享以祀，以介景福。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00360","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-37-2d-6f5b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6f5b","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-37-2d-6f5b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6f5b"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%BD%9B","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '雝', NULL, NULL, NULL, '有來雝雝，至止肅肅。相維辟公，天子穆穆。於薦廣牡，相予肆祀。
假哉皇考，綏予孝子。宣哲維人，文武維後。燕及皇天，克昌厥後。
綏我眉壽，介以繁祉。既右烈考，亦右文母。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00361","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-38-2d-96dd-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-96dd","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-38-2d-96dd-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-96dd"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%9B%9D","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '載見', NULL, NULL, NULL, '載見辟王，曰求厥章。龍旂陽陽，和鈴央央。鞗革有鶬，休有烈光。
率見昭考，以孝以享，以介眉壽，永言保之，思皇多祜。
烈文辟公，綏以多福，俾緝熙于純嘏。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00362","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-39-2d-8f09-898b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8f09-898b","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-38-39-2d-8f09-898b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8f09-898b"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%BC%89%E8%A6%8B","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '有客', NULL, NULL, NULL, '有客有客，亦白其馬。有萋有且，敦琢其旅。
有客宿宿，有客信信。言授之縶，以縶其馬。
薄言追之，左右綏之。既有淫威，降福孔夷。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00363","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-30-2d-6709-5ba2-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6709-5ba2","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-30-2d-6709-5ba2-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6709-5ba2"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%9C%89%E5%AE%A2","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '武', NULL, NULL, NULL, '於皇武王，無競維烈。
允文文王，克開厥後。
嗣武受之。勝殷遏劉，耆定爾功。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00364","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-31-2d-6b66-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6b66","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-31-2d-6b66-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6b66"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%AD%A6","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '閔予小子', NULL, NULL, NULL, '閔予小子，遭家不造，嬛嬛在疚。
於乎皇考，永世克孝，念茲皇祖，陟降庭止。
維予小子，夙夜敬止。
於乎皇王，繼序思不忘。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00365","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-32-2d-9594-4e88-5c0f-5b50-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-9594-4e88-5c0f-5b50","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-32-2d-9594-4e88-5c0f-5b50-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-9594-4e88-5c0f-5b50"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%96%94%E4%BA%88%E5%B0%8F%E5%AD%90","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '訪落', NULL, NULL, NULL, '訪予落止，率時昭考。
於乎悠哉！朕未有艾。將予就之，繼猶判渙。
維予小子，未堪家多難。紹庭上下，陟降厥家。
休矣皇考！以保明其身。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00366","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-33-2d-8a2a-843d-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8a2a-843d","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-33-2d-8a2a-843d-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8a2a-843d"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%A8%AA%E8%90%BD","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '敬之', NULL, NULL, NULL, '敬之敬之，天維顯思。
命不易哉！無曰高高在上。
陟降厥士，日監在茲。
維予小子，不聦敬止？
日就月將，學有緝熙于光明。
佛時仔肩，示我顯德行。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00367","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-34-2d-656c-4e4b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-656c-4e4b","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-34-2d-656c-4e4b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-656c-4e4b"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%95%AC%E4%B9%8B","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '小毖', NULL, NULL, NULL, '予其懲，而毖後患。莫予荓蜂，自求辛螫。
肇允彼桃蟲，拚飛維鳥。未堪家多難，予又集于蓼。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00368","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-35-2d-5c0f-6bd6-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5c0f-6bd6","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-35-2d-5c0f-6bd6-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5c0f-6bd6"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%B0%8F%E6%AF%96","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '載芟', NULL, NULL, NULL, '載芟載柞，其耕澤澤。千耦其耘，徂隰徂畛。
侯主侯伯，侯亞侯旅，侯彊侯以。
有嗿其饁，思媚其婦，有依其士。
有略其耜，俶載南畝，播厥百穀，實函斯活。
驛驛其達，有厭其傑。厭厭其苗，緜緜其麃。
載穫濟濟，有實其積，萬億及秭。
為酒為醴，烝畀祖妣，以洽百禮，有飶其香，邦家之光。
有椒其馨，胡考之寧。匪且有且，匪今斯今，振古如茲。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00369","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-36-2d-8f09-829f-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8f09-829f","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-36-2d-8f09-829f-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8f09-829f"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%BC%89%E8%8A%9F","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '良耜', NULL, NULL, NULL, '畟畟良耜，俶載南畝，播厥百穀，實函斯活。
或來瞻女，載筐及筥。其饟伊黍，其笠伊糾。
其鎛斯趙，以薅荼蓼，荼蓼朽止，黍稷茂止。
穫之挃挃，積之栗栗，其崇如墉，其比如櫛，以開百室。
百室盈止，婦子寧止。殺時犉牡，有捄其角。
以似以續，續古之人。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00370","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-37-2d-826f-801c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-826f-801c","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-37-2d-826f-801c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-826f-801c"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%89%AF%E8%80%9C","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '絲衣', NULL, NULL, NULL, '絲衣其紑，載弁俅俅。自堂徂基，自羊徂牛。
鼐鼎及鼒，兕觥其觩。旨酒思柔。不吳不敖，胡考之休。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00371","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-38-2d-7d72-8863-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7d72-8863","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-38-2d-7d72-8863-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7d72-8863"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%B5%B2%E8%A1%A3","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '酌', NULL, NULL, NULL, '於鑠王師，遵養時晦。時純熙矣，是用大介。
我龍受之，蹻蹻王之造。載用有嗣，實維爾公。
允師。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00372","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-39-2d-914c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-914c","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-39-39-2d-914c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-914c"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%85%8C","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '桓', NULL, NULL, NULL, '綏萬邦，婁豐年，天命匪解。
桓桓武王，保有厥士，于以四方。克定厥家。
於昭于天，皇以間之。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00373","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-30-2d-6853-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6853","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-30-2d-6853-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6853"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%A1%93","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '賚', NULL, NULL, NULL, '文王既勤止，我應受之。敷時繹思，我徂維求定。
時周之命，於繹思。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00374","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-31-2d-8cda-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8cda","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-31-2d-8cda-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-8cda"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%B3%9A","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '般', NULL, NULL, NULL, '於皇時周，陟其高山。嶞山喬嶽，允猶翕河。
敷天之下，裒時之對，時周之命。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00375","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-32-2d-822c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-822c","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-32-2d-822c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-822c"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E8%88%AC","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '駉', NULL, NULL, NULL, '駉駉牡馬，在坰之野。
薄言駉者，有驈有皇，有驪有黃，以車彭彭。
思無疆，思馬斯臧。
駉駉牡馬，在坰之野。
薄言駉者，有騅有駓，有騂有騏，以車伾伾。
思無期，思馬斯才。
駉駉牡馬，在坰之野。
薄言駉者，有驒有駱，有駵有雒，以車繹繹。
思無斁，思馬斯作。
駉駉牡馬，在坰之野。
薄言駉者，有駰有騢，有驔有魚，以車祛祛。
思無邪，思馬斯徂。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00376","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-33-2d-99c9-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-99c9","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-33-2d-99c9-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-99c9"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%A7%89","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '有駜', NULL, NULL, NULL, '有駜有駜，駜彼乘黃。夙夜在公，在公明明。
振振鷺，鷺于下。鼓咽咽，醉言舞。于胥樂兮。
有駜有駜，駜彼乘牡。夙夜在公，在公飲酒。
振振鷺，鷺于飛。鼓咽咽，醉言歸。于胥樂兮。
有駜有駜，駜彼乘駽。夙夜在公，在公載燕。
自今以始，歲其有。君子有穀，詒孫子。于胥樂兮。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00377","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-34-2d-6709-99dc-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6709-99dc","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-34-2d-6709-99dc-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6709-99dc"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%9C%89%E9%A7%9C","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '泮水', NULL, NULL, NULL, '思樂泮水，薄采其芹。魯侯戾止，言觀其旂。
其旂茷茷，鸞聲噦噦。無小無大，從公于邁。
思樂泮水，薄采其藻。魯侯戾止，其馬蹻蹻。
其馬蹻蹻，其音昭昭。載色載笑，匪怒伊教。
思樂泮水，薄采其茆。魯侯戾止，在泮飲酒。
既飲旨酒，永錫難老。順彼長道，屈此羣醜。
穆穆魯侯，敬明其德。敬慎威儀，維民之則。
允文允武，昭假烈祖。靡有不孝，自求伊祜。
明明魯侯，克明其德。既作泮宮，淮夷攸服。
矯矯虎臣，在泮獻馘。淑問如臯陶，在泮獻囚。
濟濟多士，克廣德心。桓桓于征，狄彼東南。
烝烝皇皇，不吳不揚。不告于訩，在泮獻功。
角弓其觩，束矢其搜。戎車孔博，徒御無斁。
既克淮夷，孔淑不逆。式固爾猶，淮夷卒獲。
翩彼飛鴞，集于泮林。食我桑黮，懷我好音。
憬彼淮夷，來獻其琛。元龜象齒，大賂南金。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00378","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-35-2d-6cee-6c34-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6cee-6c34","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-35-2d-6cee-6c34-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6cee-6c34"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%B3%AE%E6%B0%B4","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '閟宮', NULL, NULL, NULL, '閟宮有侐，實實枚枚。赫赫姜嫄，其德不回。
上帝是依，無災無害。彌月不遲，是生後稷，降之百福。
黍稷重穋，稙稺菽麥。奄有下國，俾民稼穡。
有稷有黍，有稻有秬。奄有下土，纘禹之緒。
後稷之孫，實維大王。居岐之陽，實始翦商。
至于文武，纘大王之緒。致天之屆，于牧之野。
無貳無虞，上帝臨女。敦商之旅，克咸厥功。
王曰叔父，建爾元子，俾侯于魯。大啟爾宇，為周室輔。
乃命魯公，俾侯于東。錫之山川，土田附庸。
周公之孫，莊公之子。龍旂承祀，六轡耳耳。
春秋匪解，享祀不忒。皇皇後帝，皇祖後稷。
享以騂犧，是饗是宜。降福既多，周公皇祖，亦其福女。
秋而載嘗，夏而楅衡，白牡騂剛。
犧尊將將，毛炰胾羹，籩豆大房。
萬舞洋洋，孝孫有慶。俾爾熾而昌，俾爾壽而臧。
保彼東方，魯邦是常。不虧不崩，不震不騰。
三壽作朋，如岡如陵。
公車千乘，朱英綠縢，二矛重弓。
公徒三萬，貝冑朱綅，烝徒增增。
戎狄是膺，荊舒是懲，則莫我敢承。
俾爾昌而熾，俾爾壽而富。黃髮台背，壽胥與試。
俾爾昌而大，俾爾耆而艾。萬有千歲，眉壽無有害。
泰山巖巖，魯邦所詹。奄有龜蒙，遂荒大東。
至于海邦，淮夷來同。莫不率從，魯侯之功。
保有鳧繹，遂荒徐宅。至于海邦，淮夷蠻貊。
及彼南夷，莫不率從。莫敢不諾，魯侯是若。
天錫公純嘏，眉壽保魯。居常與許，復周公之宇。
魯侯燕喜，令妻壽母。宜大夫庶士，邦國是有。
既多受祉，黃髮兒齒。
徂來之松，新甫之柏。是斷是度，是尋是尺。
松桷有舄，路寢孔碩，新廟奕奕。
奚斯所作，孔曼且碩，萬民是若。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00379","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-36-2d-959f-5bae-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-959f-5bae","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-36-2d-959f-5bae-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-959f-5bae"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%96%9F%E5%AE%AE","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '那', NULL, NULL, NULL, '猗與那與，置我鞉鼓。奏鼓簡簡，衎我烈祖。湯孫奏假，綏我思成。
鞉鼓淵淵，嘒嘒管聲，既和且平，依我磬聲。
於赫湯孫，穆穆厥聲，庸鼓有斁，萬舞有奕。
我有嘉客，亦不夷懌。自古在昔，先民有作。
溫恭朝夕，執事有恪。顧予烝嘗，湯孫之將。
猗與，歎美之言也。衎，樂也。綏，安也。斁，斁然，盛也。奕，次序也。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00380","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-37-2d-90a3-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-90a3","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-37-2d-90a3-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-90a3"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%82%A3","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '烈祖', NULL, NULL, NULL, '猗嗟嗟烈祖，有秩斯祜。申錫無疆，及爾斯所。既載清酤，賚我思成。
亦有和羹，既戒既平。鬷假無言，時靡有爭。綏我眉壽，黃耇無疆。
約軝錯衡，八鸞鶬鶬。以假以享，我受命溥將。自天降康，豐年穰穰。
來假來饗，降福無疆。顧予烝嘗，湯孫之將。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00381","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-38-2d-70c8-7956-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-70c8-7956","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-38-2d-70c8-7956-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-70c8-7956"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%83%88%E7%A5%96","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '玄鳥', NULL, NULL, NULL, '天命玄鳥，降而生商，宅殷土芒芒。古帝命武湯，正域彼四方。
方命厥後，奄有九有。商之先後，受命不殆，在武丁孫子。
武丁孫子，武王靡不勝。龍旂十乘，大糦是承。
邦畿千里，維民所止，肇域彼四海。四海來假，來假祁祁。
景員維河，殷受命咸宜，百祿是何。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00382","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-39-2d-7384-9ce5-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7384-9ce5","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-30-39-2d-7384-9ce5-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7384-9ce5"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%8E%84%E9%B3%A5","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '長發', NULL, NULL, NULL, '濬哲維商，長發其祥，洪水芒芒，禹敷下土方。
外大國是疆，幅隕既長。有娀方將，帝立子生商。
玄王桓撥，受小國是達，受大國是達。
率履不越，遂視既發。相土烈烈，海外有截。
帝命不違，至于湯齊。湯降不遟，聖敬日躋。
昭假遟遟，上帝是祗，帝命式于九圍。
受小球大球，為下國綴旒，何天之休？
不競不絿，不剛不柔，敷政優優，百祿是遒。
受小共大共，為下國駿厖，何天之龍？
敷奏其勇，不震不動，不戁不竦，百祿是總。
武王載旆，有虔秉鉞。如火烈烈，則莫我敢曷。
苞有三蘖，莫遂莫達，九有有截。韋顧既伐，昆吾夏桀。
昔在中葉，有震且業。允也天子，降予卿士。
實維阿衡，實左右商王。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00383","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-31-30-2d-9577-767c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-9577-767c","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-31-30-2d-9577-767c-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-9577-767c"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%95%B7%E7%99%BC","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '殷武', NULL, NULL, NULL, '撻彼殷武，奮伐荊楚，冞入其阻，裒荊之旅。
有截其所，湯孫之緒。
維女荊楚，居國南鄉，昔有成湯，自彼氐羌。
莫敢不來享，莫敢不來王，曰商是常。
天命多辟，設都于禹之績。
歲事來辟，勿予禍適，稼穡匪解。
天命降監，下民有嚴，不僭不濫，不敢怠遑。
命于下國，封建厥福。
商邑翼翼，四方之極，赫赫厥聲，濯濯厥靈。
壽考且寧，以保我後生。
陟彼景山，松柏丸丸，是斷是遷，方斵是虔。
松桷有梴，旅楹有閑，寢成孔安。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00384","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-31-31-2d-6bb7-6b66-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6bb7-6b66","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-33-31-31-2d-6bb7-6b66-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6bb7-6b66"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%AE%B7%E6%AD%A6","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '節南山', NULL, NULL, NULL, '節南山
節彼南山，維石巖巖。赫赫師尹，民具爾瞻。
憂心如惔，不敢戲談。國既卒斬，何用不監！
節彼南山，有實其猗。赫赫師尹，不平謂何？
天方薦瘥，喪亂弘多。民言無嘉，憯莫懲嗟。
尹氏大師，維周之氐。秉國之均，四方是維。
天子是毗，俾民不迷。不弔昊天，不宜空我師。
弗躬弗親，庶民弗信；弗問弗仕，勿罔君子？
式夷式已，無小人殆。瑣瑣姻亞，則無膴仕。
昊天不傭，降此鞠訩。昊天不惠，降此大戾。
君子如屆，俾民心闋。君子如夷，惡怒是違。
不弔昊天，亂靡有定。式月斯生，俾民不寧。
憂心如酲，誰秉國成？不自為政，卒勞百姓。
駕彼四牡，四牡項領。我瞻四方，蹙蹙靡所騁。
方茂爾惡，相爾矛矣。既夷既懌，如相醻矣。
昊天不平，我王不寧。不懲其心，覆怨其正。
家父作誦，以究王訩。式訛爾心，以畜萬邦。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00385","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-31-39-37-2d-7bc0-5357-5c71-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7bc0-5357-5c71","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-31-39-37-2d-7bc0-5357-5c71-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-7bc0-5357-5c71"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E7%AF%80%E5%8D%97%E5%B1%B1","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '正月', NULL, NULL, NULL, '正月繁霜，我心憂傷。民之訛言，亦孔之將。
念我獨兮，憂心京京。哀我小心，癙憂以痒。
父母生我，胡俾我瘉？不自我先，不自我後。
好言自口，莠言自口。憂心愈愈，是以有侮。
憂心惸惸，念我無祿。民之無辜，並其臣僕。
哀我人斯，于何從祿？瞻烏爰止，于誰之屋？
瞻彼中林，侯薪侯蒸。民今方殆，視天夢夢。
既克有定，靡人弗勝。有皇上帝，伊誰雲憎？
謂山蓋卑，為岡為陵。民之訛言，寧莫之懲！
召彼故老，訊之占夢。具曰予聖，誰知烏之雌雄？
謂天蓋高，不敢不局。謂地蓋厚，不敢不蹐。
維號斯言，有倫有脊。哀今之人，胡為虺蜴。
瞻彼阪田，有菀其特。天之扤我，如不我克。
彼求我則，如不我得。執我仇仇，亦不我力。
心之憂矣，如或結之。今茲之正，胡然厲矣？
燎之方揚，寧或滅之。赫赫宗周，褒姒烕之。
終其永懷，又窘陰雨。其車既載，乃棄爾輔。
載輸爾載，將伯助予。
無棄爾輔，員于爾輻。屢顧爾僕，不輸爾載。
終踰絶險，曾是不意。
魚在于沼，亦匪克樂。潛雖伏矣，亦孔之炤。
憂心慘慘，念國之為虐。
彼有旨酒，又有嘉殽。洽比其鄰，昏姻孔雲。
念我獨兮，憂心慇慇。
佌佌彼有屋，蔌蔌方有穀。民今之無祿，天夭是椓。
哿矣富人，哀此惸獨！', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00386","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-31-39-38-2d-6b63-6708-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6b63-6708","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-31-39-38-2d-6b63-6708-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-6b63-6708"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E6%AD%A3%E6%9C%88","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '十月之交', NULL, NULL, NULL, '十月之交，朔月辛卯。日有食之，亦孔之醜。
彼月而微，此日而微。今此下民，亦孔之哀。
日月告凶，不用其行。四國無政，不用其良。
彼月而食，則維其常。此日而食，于何不臧？
爗爗震電，不寧不令。百川沸騰，山冡崒崩。
高岸為谷，深谷為陵。哀今之人，胡憯莫懲？
皇父卿士，番維司徒。家伯維宰，仲允膳夫。
棸子內史，蹶維趣馬。楀維師氏，豔妻煽方處。
抑此皇父，豈曰不時？胡為我作，不即我謀？
徹我牆屋，田卒汙萊。曰予不戕，禮則然矣！
皇父孔聖，作都于向。擇三有事，亶侯多藏。
不憖遺一老，俾守我王。擇有車馬，以居徂向。
黽勉從事，不敢告勞。無罪無辜，讒口嚻嚻。
下民之孽，匪降自天。噂沓背憎，職競由人。
悠悠我里，亦孔之痗。四方有羨，我獨居憂。
民莫不逸，我獨不敢休。天命不徹，我不敢傚我友自逸。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00387","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-31-39-39-2d-5341-6708-4e4b-4ea4-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5341-6708-4e4b-4ea4","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-31-39-39-2d-5341-6708-4e4b-4ea4-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5341-6708-4e4b-4ea4"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%8D%81%E6%9C%88%E4%B9%8B%E4%BA%A4","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '雨無正', NULL, NULL, NULL, '浩浩昊天，不駿其德。降喪饑饉，斬伐四國。
旻天疾威，弗慮弗圖。舍彼有罪，既伏其辜。若此無罪，淪胥以鋪。
周宗既滅，靡所止戾，正大夫離居，莫知我勩。
三事大夫，莫肯夙夜。邦君諸侯，莫肯朝夕。庶曰式臧，覆出為惡。
如何昊天，辟言不信？如彼行邁，則靡所臻。
凡百君子，各敬爾身。胡不相畏？不畏于天？
戎成不退，飢成不遂。曾我暬御，憯憯日瘁。
凡百君子，莫肯用訊。聽言則荅，譖言則退。
哀哉不能言，匪舌是出，維躬是瘁。
哿矣能言，巧言如流，俾躬處休。
維曰予仕，孔棘且殆。雲不可使，得罪于天子。
亦雲可使，怨及朋友。
謂爾遷于王都，曰予未有室家。
鼠思泣血，無言不疾。昔爾出居，誰從作爾室？', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00388","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-30-2d-96e8-7121-6b63-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-96e8-7121-6b63","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-30-2d-96e8-7121-6b63-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-96e8-7121-6b63"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E9%9B%A8%E7%84%A1%E6%AD%A3","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '小旻', NULL, NULL, NULL, '旻天疾威，敷于下土，謀猶回遹，何日斯沮？
謀臧不從，不臧覆用。我視謀猶，亦孔之卭。
潝潝訿訿，亦孔之哀。謀之其臧，則具是違。
謀之不臧，則具是依。我視謀猶，伊于胡厎？
我龜既厭，不我告猶。謀夫孔多，是用不集。
發言盈庭，誰敢執其咎？如匪行邁謀，是用不得于道。
哀哉為猶！匪先民是程，匪大猶是經。
維邇言是聽，維邇言是爭。如彼築室于道謀，是用不潰于成。
國雖靡止，或聖或否。民雖靡膴，或哲或謀，或肅或艾。
如彼泉流，無淪胥以敗。
不敢暴虎，不敢馮河。人知其一，莫知其他。
戰戰兢兢，如臨深淵，如履薄冰。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00389","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-31-2d-5c0f-65fb-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5c0f-65fb","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-31-2d-5c0f-65fb-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5c0f-65fb"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%B0%8F%E6%97%BB","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '小宛', NULL, NULL, NULL, '宛彼鳴鳩，翰飛戾天。我心憂傷，念昔先人。明發不寐，有懷二人。
人之齊聖，飲酒溫克。彼昏不知，壹醉日富。各敬爾儀，天命不又。
中原有菽，庶民采之。螟蛉有子，蜾蠃負之。教誨爾子，式穀似之。
題彼脊令，載飛載鳴。我日斯邁，而月斯征。夙興夜寐，毋忝爾所生。
交交桑扈，率場啄粟。哀我填寡，宜岸宜獄。握粟出卜，自何能穀？
溫溫恭人，如集于木。惴惴小心，如臨于谷。戰戰兢兢，如履薄冰。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00390","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-32-2d-5c0f-5b9b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5c0f-5b9b","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-32-2d-5c0f-5b9b-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5c0f-5b9b"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%B0%8F%E5%AE%9B","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '小弁', NULL, NULL, NULL, '弁彼鸒斯，歸飛提提。民莫不穀，我獨于罹。
何辜于天，我罪伊何？心之憂矣，雲如之何。
踧踧周道，鞫為茂草。我心憂傷，惄焉如擣。
假寐永歎，維憂用老。心之憂矣，疢如疾首。
維桑與梓，必恭敬止。靡瞻匪父，靡依匪母。
不屬于毛？不罹于裏？天之生我，我辰安在？
菀彼柳斯，鳴蜩嘒嘒。有漼者淵，萑葦淠淠。
譬彼舟流，不知所屆。心之憂矣，不遑假寐。
鹿斯之奔，維足伎伎。雉之朝雊，尚求其雌。
譬彼壞木，疾用無枝。心之憂矣，寧莫之知。
相彼投兔，尚或先之。行有死人，尚或墐之。
君子秉心，維其忍之。心之憂矣，涕既隕之。
君子信讒，如或醻之。君子不惠，不舒究之。
伐木掎矣，析薪扡矣。舍彼有罪，予之佗矣。
莫高匪山，莫浚匪泉。君子無易由言，耳屬于垣。
無逝我梁，無發我笱。我躬不閱，遑恤我後。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00391","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-33-2d-5c0f-5f01-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5c0f-5f01","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-33-2d-5c0f-5f01-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5c0f-5f01"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%B0%8F%E5%BC%81","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '巧言', NULL, NULL, NULL, '悠悠昊天，曰父母且。無罪無辜，亂如此幠。
昊天已威，予慎無罪。昊天大幠，予慎無辜。
亂之初生，僭始既涵。亂之又生，君子信讒。
君子如怒，亂庶遄沮。君子如祉，亂庶遄已。
君子屢盟，亂是用長。君子信盜，亂是用暴。
盜言孔甘，亂是用餤。匪其止共，維王之卭。
奕奕寢廟，君子作之。秩秩大猷，聖人莫之。
他人有心，予忖度之。躍躍毚兔，遇犬獲之。
荏染柔木，君子樹之。往來行言，心焉數之。
蛇蛇碩言，出自口矣。巧言如簧，顏之厚矣。
彼何人斯？居河之麋。無拳無勇，職為亂階。
既微且尰，爾勇伊何！為猶將多，爾居徒幾何！', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00392","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-34-2d-5de7-8a00-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5de7-8a00","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-34-2d-5de7-8a00-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5de7-8a00"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%B7%A7%E8%A8%80","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '何人斯', NULL, NULL, NULL, '彼何人斯？其心孔艱。胡逝我梁，不入我門？伊誰雲從？維暴之雲。
二人從行，誰為此禍？胡逝我梁，不入唁我？始者不如今，雲不我可。
彼何人斯，胡逝我陳？我聞其聲，不見其身。不愧于人。不畏于天。
彼何人斯？其為飄風。胡不自北？胡不自南？胡逝我梁？祇攪我心。
爾之安行，亦不遑舍。爾之亟行，遑脂爾車？壹者之來，雲何其盱。
爾還而入，我心易也。還而不入，否難知也。壹者之來，俾我祇也。
伯氏吹壎，仲氏吹篪。及爾如貫，諒不我知。出此三物，以詛爾斯。
為鬼為蜮，則不可得。有靦面目，視人罔極。作此好歌，以極反側。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00393","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-35-2d-4f55-4eba-65af-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-4f55-4eba-65af","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-35-2d-4f55-4eba-65af-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-4f55-4eba-65af"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E4%BD%95%E4%BA%BA%E6%96%AF","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-3fcc3c660d5a7a4d', 0, '巷伯', NULL, NULL, NULL, '萋兮斐兮，成是貝錦。彼譖人者，亦已大甚。
哆兮侈兮，成是南箕。彼譖人者，誰適與謀？
緝緝翩翩，謀欲譖人。慎爾言也，謂爾不信。
捷捷幡幡，謀欲譖言。豈不爾受？既其女遷。
驕人好好，勞人草草。蒼天蒼天！視彼驕人，矜此勞人！
彼譖人者，誰適與謀？取彼譖人，投畀豺虎。
豺虎不食，投畀有北。有北不受，投畀有昊。
楊園之道，猗于畝丘。寺人孟子，作為此詩。
凡百君子，敬而聽之。', 'parsed', 'cnpt-shijing', '{"queue_id":"CN-TR-00394","source_record_id":"CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-36-2d-5df7-4f2f-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5df7-4f2f","alias_record_ids":["CN-CLASSIC-73-68-69-6a-69-6e-67-2d-32-30-36-2d-5df7-4f2f-2d-4f5a-540d-2f-8a69-7d93-2d-8a69-7d93-2f-5df7-4f2f"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E8%A9%A9%E7%B6%93/%E5%B7%B7%E4%BC%AF","review_status":"needs-review","review_reasons":["classic-index-work","shijing"]}'),
    ('cnpreqin-d9cfb1495fcebc18', 0, '九章', NULL, NULL, NULL, '惜誦以致愍兮，發憤以杼情。所作忠而言之兮，指蒼天以爲正。令五帝以㭊中兮，戒六神與嚮服。俾山川以備御兮，命咎繇使聽直。竭忠誠以事君兮，反離羣而贅肬。忘儇媚以背衆兮，待明君其知之。言與行其可迹兮，情與貌其不變。故相臣莫若君兮，所以證之不遠。吾誼先君而後身兮，羌衆人之所仇。專惟君而無他兮，又衆兆之所讎。壹心而不豫兮，羌不可保也。疾親君而無他兮，有招禍之道也。
思君其莫我忠兮，忽忘身之賤貧。事君而不貳兮，迷不知寵之門。忠何罪以遇罰兮，亦非餘心之所志。行不羣以巔越兮，又衆兆之所咍。紛逢尤以離謗兮，謇不可釋。情沈抑而不達兮，又蔽而莫之白。心鬱邑餘侘傺兮，又莫察餘之中情。固煩言不可結詒兮，願陳志而無路。退靜默而莫餘知兮，進號呼又莫吾聞。申侘傺之煩惑兮，中悶瞀之忳忳。
昔餘夢登天兮，魂中道而無杭。吾使厲神占之兮，曰有志極而無旁。終危獨以離異兮，曰君可思而不可恃。故衆口其鑠金兮，初若是而逢殆。懲於羹者而吹䪠兮，何不變此志也？欲釋階而登天兮，猶有曩之態也。衆駭遽以離心兮，又何以爲此伴也？同極而異路兮，又何以爲此援也？晉申生之孝子兮，父信讒而不好。行婞直而不豫兮，鮌功用而不就。
吾聞作忠以造怨兮，忽謂之過言。九折臂而成醫兮，吾至今而知其信然。矰弋機而在上兮，罻羅張而在下。設張辟以娛君兮，願側身而無所。欲儃佪以乾傺兮，恐重患而離尤。欲高飛而遠集兮，君罔謂汝何之？欲橫奔而失路兮，堅志而不忍。背膺牉以交痛兮，心鬱結而紆軫。檮木蘭以矯蕙兮，糳申椒以爲糧。播江離與滋菊兮，願春日以爲糗芳。恐情質之不信兮，故重著以自明。矯兹媚以私處兮，願曾思而遠身。
餘幼好此奇服兮，年既老而不衰。帶長鋏之陸離兮，冠切雲之崔嵬。被明月兮珮寶璐，世溷濁而莫餘知兮，吾方高馳而不顧。駕青虬兮驂白螭，吾與重華遊兮瑤之圃。登崑崙兮食玉英，與天地兮同壽，與日月兮同光。哀南夷之莫吾知兮，旦餘濟乎江湘。
乘鄂渚而反顧兮，欸秋冬之緒風。步餘馬兮山皋，邸餘車兮方林。乘舲船餘上沅兮，齊吳榜以擊汰。船容與而不進兮，淹回水而疑滯。朝發枉陼兮，夕宿辰陽。苟餘心其端直兮，雖僻遠之何傷。
入漵浦餘儃佪兮，迷不知吾所如。深林杳以冥冥兮，猨狖之所居。山峻高以蔽日兮，下幽晦以多雨。霰雪紛其無垠兮，雲霏霏而承宇。哀吾生之無樂兮，幽獨處乎山中。吾不能變心而從俗兮，固將愁苦而終窮。
接輿髡首兮，桑扈臝行。忠不必用兮，賢不必以。伍子逢殃兮，比乾菹醢。與前世而皆然兮，吾又何怨乎今之人。餘將董道而不豫兮，固將重昏而終身。
亂曰：鸞鳥鳳皇，日以遠兮。燕雀烏鵲，巢堂壇兮。露申辛夷，死林薄兮。腥臊並御，芳不得薄兮。陰陽易位，時不當兮。懷信侘傺，忽乎吾將行兮。
皇天之不純命兮，何百姓之震愆。民離散而相失兮，方仲春而東遷。去故鄉而就遠兮，遵江夏以流亡。出國門而軫懷兮，甲之鼂吾以行。發郢都而去閭兮，荒忽其焉極。楫齊揚以容與兮，哀見君而不再得。望長楸而太息兮，涕淫淫其若霰。過夏首而西浮兮，顧龍門而不見。心嬋媛而傷懷兮，眇不知其所蹠。順風波以從流兮，焉洋洋而爲客。淩陽侯之氾濫兮，忽翱翔之焉薄。心絓結而不解兮，思蹇產而不釋。將運舟而下浮兮，上洞庭而下江。去終古之所居兮，今逍遥而來東。
羌靈䰟之欲歸兮，何須臾而忘反。背夏浦而西思兮，哀故都之日遠。登大墳以遠望兮，聊以舒吾憂心。哀州土之平樂兮，悲江介之遺風。當陵陽之焉至兮，淼南渡之焉如。曾不知夏之爲丘兮，孰兩東門之可蕪？心不怡之長久兮，憂與愁其相接。惟郢路之遼遠兮，江與夏之不可涉。忽若不信兮，至今九年而不復。慘鬱鬱而不通兮，蹇侘傺而含慼。
外承歡之汋約兮，諶荏弱而難持。忠湛湛而願進兮，妬被離而鄣之。堯舜之抗行兮，瞭杳杳而薄天。衆讒人之嫉妬兮，被以不慈之僞名。憎愠惀之脩美兮，好夫人之忼慨。衆踥蹀而日進兮，美超遠而逾邁。
亂曰：曼餘目以流觀兮，冀壹反之何時。鳥飛反故鄉兮，狐死必首丘。信非吾罪而棄逐兮，何日夜而忘之！
心鬱鬱之憂思兮，獨永歎乎增傷。思蹇產之不釋兮，曼遭夜之方長。悲秋風之動容兮，何回極之浮浮。數惟蓀之多怒兮，傷餘心之懮懮。願摇起而橫奔兮，覽民尤以自鎮。結微情以陳詞兮，矯以遺夫美人。昔君與我誠言兮，曰黃昏以爲期。羌中道而回畔兮，反既有此他志。憍吾以其美好兮，覽餘以其脩姱。與餘言而不信兮，蓋爲餘而造怒。
願承閒而自察兮，心震悼而不敢。悲夷猶而冀進兮，心怛傷之憺憺。兹歷情以陳辭兮，蓀詳聾而不聞。固切人之不媚兮，衆果以我爲患。初吾所陳之耿著兮，豈至今其庸亡。何毒藥之謇謇兮，願蓀美之可完。望三五以爲像兮，指彭咸以爲儀。夫何極而不至兮，故遠聞而難虧。善不由外來兮，名不可以虛作。孰無施而有報兮，孰不實而有穫？
少歌曰：與美人抽怨兮，並日夜而無正。憍吾以其美好兮，敖朕辭而不聽。
倡曰：有鳥自南兮，來集漢北。好姱佳麗兮，牉獨處此異域。既惸獨而不羣兮，又無良媒在其側。道卓遠而日忘兮，願自申而不得。望丘山而流涕兮，臨流水而太息。望孟夏之短夜兮，何晦明之若歲。惟郢路之遼遠兮，䰟一夕而九逝。曾不知路之曲直兮，南指月與列星。願徑逝而未得兮，魂識路之營營。何靈䰟之信直兮，人之心不與吾心同。理弱而媒不通兮，尚不知餘之從容。
亂曰：長瀨湍流，泝江潭兮。狂顧南行，聊以娛心兮。軫石崴嵬，蹇吾願兮。超回志度，行隱進兮。低佪夷猶，宿北姑兮。煩寃瞀容，實沛徂兮。愁歎苦神，靈遥思兮。路遠處幽，又無行媒兮。道思作頌，聊以自救兮。憂心不遂，斯言誰告兮。
滔滔孟夏兮，草木莽莽。傷懷永哀兮，汩徂南土。眴兮杳杳，孔靜幽默。鬱結紆軫兮，離慜而長鞠。撫情効志兮，寃屈而自抑。
刓方以爲圜兮，常度未替。易初伓迪兮，君子所鄙。章畫志墨兮，前圖未改。內厚質正兮，大人所盛。巧倕不斲兮，孰察其撥正。
玄文處幽兮，矇瞍謂之不章。離婁微睇兮，瞽以爲無明。變白以爲黑兮，倒上以爲下。鳳皇在笯兮，雞鶩翔舞。同糅玉石兮，一槩而相量。夫惟黨人鄙固兮，羌不知餘之所臧。任重載盛兮，陷滯而不濟。懷瑾握瑜兮，窮不知所示。邑犬之羣吠兮，吠所怪也。非俊疑傑兮，固庸態也。文質疏內兮，衆不知餘之異采。材樸委積兮，莫知餘之所有。
重仁襲義兮，謹厚以爲豐。重華不可𨕓兮，孰知餘之從容？古固有不並兮，豈知其何故。湯禹久遠兮，邈而不可慕。懲連改忿兮，抑心而自強。離慜而不遷兮，願志之有像。進路北次兮，日昧昧其將暮。舒憂娛哀兮，限之以大故。
亂曰：浩浩沅湘，分流汩兮。脩路幽蔽，道遠忽兮。懷質抱情，獨無匹兮。伯樂既沒，驥焉程兮？萬民之生，各有所錯兮。定心廣志，餘何畏懼兮？曾傷爰哀，永歎喟兮。世溷濁莫吾知，人心不可謂兮。知死不可讓，願勿愛兮。明告君子，吾將以爲類兮。
思美人兮，擥涕而竚眙。媒絶路阻兮，言不可結而詒。蹇蹇之煩寃兮，陷滯而不發。申旦以舒中情兮，志沈菀而莫達。願寄言於浮雲兮，遇豐隆而不將。因歸鳥而致辭兮，羌宿高而難當。高辛之靈盛兮，遭玄鳥而致詒。欲變節以從俗兮，媿易初而屈志。獨歷年而離愍兮，羌馮心猶未化。寧隱閔而壽考兮，何變易之可爲。
知前轍之不遂兮，未改此度。車既覆而馬顛兮，蹇獨懷此異路。勒騏驥而更駕兮，造父爲我操之。遷逡次而勿驅兮，聊假日以須旹。指嶓冢之西隈兮，與纁黃以爲期。
開春發歲兮，白日出之悠悠。吾將蕩志而愉樂兮，遵江夏以娛憂。擥大薄之芳茝兮，搴長洲之宿莽。惜吾不及古人兮，吾誰與玩此芳草？解萹薄與雜菜兮，備以爲交佩。佩繽紛以繚轉兮，遂萎絶而離異。吾且儃佪以娛憂兮，觀南人之變態。竊快在中心兮，揚厥憑而不竢。
芳與澤其雜糅兮，羌芳華自中出。紛郁郁其遠承兮，滿內而外揚。情與質信可保兮，羌居蔽而聞章。令薜荔以爲理兮，憚舉趾而緣木。因芙蓉而爲媒兮，憚蹇裳而濡足。登高吾不說兮，入下吾不能。固朕形之不服兮，然容與而狐疑。廣遂前畫兮，未改此度也。命則處幽，吾將罷兮，願及白日之未暮。獨焭焭而南行兮，思彭咸之故也。
惜往日之曾信兮，受命詔以昭詩。奉先功以照下兮，明法度之嫌疑。國富強而法立兮，屬貞臣而日娭。秘密事之載心兮，雖過失猶弗治。心純庬而不泄兮，遭讒人而嫉之。君含怒而待臣兮，不清澈其然否。蔽晦君之聰明兮，虛惑誤又以欺。弗參驗以考實兮，遠遷臣而弗思。信讒諛之溷濁兮，盛氣志而過之。何貞臣之無辠兮，被離謗而見尤。慙光景之誠信兮，身幽隱而備之。臨沅湘之玄淵兮，遂自忍而沈流。卒沒身而絶名兮，惜壅君之不昭。君無度而弗察兮，使芳草爲藪幽。焉舒情而抽信兮，恬死亡而不聊。獨鄣壅而蔽隱兮，使貞臣爲無由。
聞百里之爲虜兮，伊尹烹於庖廚。呂望屠於朝歌兮，甯戚歌而飯牛。不逢湯武與桓繆兮，世孰雲而知之？吳信讒而弗味兮，子胥死而後憂。介子忠而立枯兮，文君寤而追求。封介山而爲之禁兮，報大德之優遊。思久故之親身兮，因縞素而哭之。或忠信而死節兮，或訑謾而不疑。弗省察而按實兮，聽讒人之虛辭。芳與澤其雜糅兮，孰申旦而別之？何芳草之早殀兮，微霜降而下戒。諒聰不明而蔽壅兮，使讒諛而日得。自前世之嫉賢兮，謂蕙若其不可佩。妬佳冶之芬芳兮，𡠜母姣而自好。雖有西施之美容兮，讒妬入以自代。願陳情以白行兮，得罪過之不意。情寃見之日明兮，如列宿之錯置。乘騏驥而馳騁兮，無轡銜而自載。乘氾泭以下流兮，無舟楫而自備。背法度而心治兮，辟與此其無異。寧溘死而流亡兮，恐禍殃之有再。不畢辭而赴淵兮，惜壅君之不識。
後皇嘉樹，橘徠服兮。受命不遷，生南國兮。深固難徙，更壹志兮。綠葉素榮，紛其可喜兮。曾枝剡棘，圓果摶兮。青黃雜糅，文章爛兮。精色內白，類可任兮。紛緼宜脩，姱而不醜兮。
嗟爾幼志，有以異兮。獨立不遷，豈不可喜兮？深固難徙，廓其無求兮。蘇世獨立，橫而不流兮。閉心自慎，不終失過兮。秉德無私，參天地兮。願歲並謝，與長友兮。淑離不淫，梗其有理兮。年歲雖少，可師長兮。行比伯夷，置以爲像兮。
悲回風之摇蕙兮，心寃結而內傷。物有微而隕性兮，聲有隱而先倡。夫何彭咸之造思兮，暨志介而不忘。萬變其情豈可蓋兮，孰虛僞之可長。鳥獸鳴以號群兮，草苴比而不芳。魚葺鱗以自別兮，蛟龍隱其文章。故荼薺不同畝兮，蘭茝幽而獨芳。惟佳人之永都兮，更統世而自貺。眇遠志之所及兮，憐浮雲之相羊。介眇志之所惑兮，竊賦詩之所明。
惟佳人之獨懷兮，折若椒以自處。曾歔欷之嗟嗟兮，獨隱伏而思慮。涕泣交而凄凄兮，思不眠以至曙。終長夜之曼曼兮，掩此哀而不去。寤從容以周流兮，聊逍遥以自恃。傷太息之愍憐兮，氣於邑而不可止。糺思心以爲纕兮，編愁苦以爲膺。折若木以蔽光兮，隨飄風之所仍。存髣髴而不見兮，心踊躍其若湯。撫珮衽以案志兮，超惘惘而遂行。歲曶曶其若頽兮，旹亦冉冉而將至。薠蘅槁而節離兮，芳以歇而不比。憐思心之不可懲兮，證此言之不可聊。寧逝死而流亡兮，不忍爲此之常愁。孤子唫而抆淚兮，放子出而不還。孰能思而不隱兮，照彭咸之所聞。
登石巒以遠望兮，路眇眇之默默。入景響之無應兮，聞省想而不可得。愁鬱鬱之無快兮，處戚戚而不可解。心鞿羈而不形兮，氣繚轉而自締。穆眇眇之無垠兮，莽芒芒之無儀。聲有隱而相感兮，物有純而不可爲。藐蔓蔓之不可量兮，縹綿綿之不可紆。愁悄悄之常悲兮，翩冥冥之不可娛。淩大波而流風兮，託彭咸之所居。
上高巖之峭岸兮，處雌蜺之標顛。據青冥而攄虹兮，遂儵忽而捫天。吸湛露之浮源兮，漱凝霜之雰雰。依風穴以自息兮，忽傾寤以嬋媛。馮崑崙以瞰霧兮，隱㞶山以清江。憚涌湍之礚礚兮，聽波聲之洶洶。紛容容之無經兮，罔芒芒之無紀。軋洋洋之無從兮，馳委移之焉止。漂翻翻其上下兮，翼遥遥其左右。氾潏潏其前後兮，伴張㢮之信期。觀炎氣之相仍兮，窺煙液之所積。悲霜雪之俱下兮，聽潮水之相擊。借光景以往來兮，施黃棘之枉策。求介子之所存兮，見伯夷之放迹。心調度而弗去兮，刻著志之無適。
曰：吾怨往昔之所冀兮，悼來者之悐悐。浮江淮而入海兮，從子胥而自適。望大河之洲渚兮，悲申徒之抗迹。驟諫君而不聽兮，重任石之何益。心絓結而不解兮，思蹇產而不釋。', 'parsed', 'cnpt-chuci', '{"queue_id":"CN-TR-00395","source_record_id":"CN-CLASSIC-63-68-75-63-69-2d-34-2d-4e5d-7ae0-2d-5c48-539f-2d-695a-8fad-2f-4e5d-7ae0","alias_record_ids":["CN-CLASSIC-63-68-75-63-69-2d-34-2d-4e5d-7ae0-2d-5c48-539f-2d-695a-8fad-2f-4e5d-7ae0"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E6%A5%9A%E8%BE%AD/%E4%B9%9D%E7%AB%A0","review_status":"needs-review","review_reasons":["classic-index-work","chuci"]}'),
    ('cnpreqin-d9cfb1495fcebc18', 0, '漁父', NULL, NULL, NULL, '屈原既放，遊於江潭，行吟澤畔，顏色憔悴，形容枯槁。漁父見而問之曰：「子非三閭大夫與？何故至於斯？」屈原曰：「舉世皆濁我獨清，衆人皆醉我獨醒，是以見放。」漁父曰：「聖人不凝滯於物，而能與世推移。世人皆濁，何不淈其泥而揚其波？衆人皆醉，何不餔其糟而歠其釃？何故深思高舉，自令放爲？」屈原曰：「吾聞之，新沐者必彈冠，新浴者必振衣。安能以身之察察，受物之汶汶者乎？寧赴湘流，葬於江魚之腹中，安能以皓皓之白，而蒙世俗之塵埃乎？」漁父莞爾而笑，鼓枻而去，歌曰：「滄浪之水清兮，可以濯吾纓；滄浪之水濁兮，可以濯吾足。」遂去，不復與言。', 'parsed', 'cnpt-chuci', '{"queue_id":"CN-TR-00396","source_record_id":"CN-CLASSIC-63-68-75-63-69-2d-37-2d-6f01-7236-2d-5c48-539f-2d-6f01-7236","alias_record_ids":["CN-CLASSIC-63-68-75-63-69-2d-37-2d-6f01-7236-2d-5c48-539f-2d-6f01-7236"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E6%BC%81%E7%88%B6","review_status":"needs-review","review_reasons":["classic-index-work","chuci"]}'),
    ('cnpreqin-d9cfb1495fcebc18', 0, '大招', NULL, NULL, NULL, '青春受𧬄，白日昭只。春氣奮發，萬物遽只。冥淩浹行，魂無逃只。魂魄歸徠，無遠遥只！魂乎歸徠，無東無西，無南無北只！東有大海，溺水浟浟只。螭龍竝流，上下悠悠只。霧雨淫淫，白皓膠只。魂乎無東，湯谷𡧯只。魂乎無南，南有炎火千里，蝮蛇蜒只。山林險隘，虎豹蜿只。鰅鳙短狐，王虺騫只。魂乎無南，蜮傷躬只。魂乎無西，西方流沙，漭洋洋只。豕首縱目，被發鬤只。長爪踞牙，誒笑狂只。魂乎無西，多害傷只。魂乎無北，北有寒山，逴龍赩只。代水不可涉，深不可測只。天白顥顥，寒凝凝只。魂乎無往，盈北極只。魂魄歸徠，間以靜只！
自恣荆楚，安以定只。逞志究欲，心意安只。窮身永樂，年壽延只。魂乎歸徠，樂不可言只！五穀六仞，設菰粱只。鼎臑盈望，和致芳只。內鶬鴿鵠，味豺羹只。魂乎歸徠，恣所嘗只！鮮蠵甘鷄，和楚酪只。醢豚苦狗，膾苴蒪只。吳酸蒿蔞，不沾薄只。魂兮歸徠，恣所擇只！炙鴰烝鳧，煔鶉敶只。煎鰿𦞦雀，遽爽存只。魂乎歸徠，麗以先只！四酎並孰，不歰嗌只。清馨凍𣤗，不歠役只。吳醴白糵，和楚瀝只。魂乎歸徠，不遽惕只！
代秦鄭衛，鳴竽張只。伏戲駕辯，楚勞商只。謳和揚阿，趙簫倡只。魂乎歸徠，定空桑只！二八接舞，投詩賦只。叩鍾調磬，娛人亂只。四上競氣，極聲變只。魂乎歸徠，聽歌譔只！朱脣皓齒，嫭以姱只。比德好間，習以都只。豐肉微骨，調以娛只。魂乎歸徠，安以舒只！嫮目宜笑，娥眉曼只。容則秀雅，穉朱顏只。魂乎歸徠，靜以安只！姱脩滂浩，麗以佳只。曾頰倚耳，曲眉規只。滂心綽態，姣麗施只。小腰秀頸，若鮮卑只。魂乎歸徠，思怨移只！易中利心，以動作只。粉白黛黑，施芳澤只。長袂拂面，善留客只。魂乎歸徠，以娛昔只！青色直眉，美目媔只。靨輔奇牙，宜笑嘕只。豐肉微骨，體便娟只。魂乎歸徠，恣所便只！
夏屋廣大，沙堂秀只。南房小壇，觀絶霤只。曲屋步壛，宜擾畜只。騰駕步遊，獵春囿只。瓊轂錯衡，英華假只。茝蘭桂樹，鬱彌路只。魂乎歸徠，恣志慮只！孔雀盈園，畜鸞皇只。鵾鴻群晨，雜𪃩鶬只。鴻鵠代遊，曼鷫鷞只。魂乎歸徠，鳳皇翔只！曼澤怡面，血氣盛只。永宜厥身，保壽命只。室家盈廷，爵祿盛只。魂乎歸徠，居室定只！接徑千里，出若雲只。三圭重侯，聽類神只。察篤夭隱，孤寡存只。魂兮歸徠，正始昆只！
田邑千畛，人阜昌只。美冒衆流，德澤章只。先威後文，善美明只。魂乎歸徠，賞罰當只！名聲若日，照四海只。德譽配天，萬民理只。北至幽陵，南交阯只。西薄羊腸，東窮海只。魂乎歸徠，尚賢士只！發政獻行，禁苛暴只。舉傑壓陛，誅譏罷只。直贏在位，近禹麾只。豪傑執政，流澤施只。魂乎歸徠，國家爲只！雄雄赫赫，天德明只。三公穆穆，登降堂只。諸侯畢極，立九卿只。昭質既設，大侯張只。執弓挾矢，揖辭讓只。魂乎徠歸，尚三王只！', 'parsed', 'cnpt-chuci', '{"queue_id":"CN-TR-00397","source_record_id":"CN-CLASSIC-63-68-75-63-69-2d-31-30-2d-5927-62db-2d-5c48-539f-2d-695a-8fad-2f-5927-62db","alias_record_ids":["CN-CLASSIC-63-68-75-63-69-2d-31-30-2d-5927-62db-2d-5c48-539f-2d-695a-8fad-2f-5927-62db"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E6%A5%9A%E8%BE%AD/%E5%A4%A7%E6%8B%9B","review_status":"needs-review","review_reasons":["classic-index-work","chuci"]}'),
    ('cnpreqin-7ffd49878d637ea2', 0, '九歎', NULL, NULL, NULL, '伊伯庸之末胄兮，諒皇直之屈原。雲餘肇祖于高陽兮，惟楚懷之𡠐連。原生受命于貞節兮，鴻永路有嘉名。齊名字於天地兮，並光明於列星。吸精粹而吐氛濁兮，橫邪世而不取容。行叩誠而不阿兮，遂見排而逢讒。後聽虛而黜實兮，不吾理而順情。腸憤悁而含怒兮，志遷蹇而左傾。心戃慌其不我與兮，躳速速其不吾親。辭靈脩而隕志兮，吟澤畔之江濱。椒桂羅㠯顛覆兮，有竭信而歸誠。讒夫藹藹而漫著兮，曷其不舒予情？
始結言於廟堂兮，信中塗而叛之。懷蘭蕙與衡芷兮，行中壄而散之。聲哀哀而懷高丘兮，心愁愁而思舊邦。願承閒而自恃兮，徑淫曀而道𡔏。顏黴黧以沮敗兮，精越裂而衰耄。裳襜襜而含風兮，衣納納而掩露。赴江湘之湍流兮，順波湊而下降。徐徘徊於山阿兮，飄風來之洶洶。馳餘車兮玄石，步餘馬兮洞庭。平明發兮蒼梧，夕投宿兮石城。芙蓉蓋而蔆華車兮，紫貝闕而玉堂。薜荔飾而陸離薦兮，魚鱗衣而白蜺裳。登逢龍而下隕兮，違故鄉之漫漫。思南郢之舊俗兮，腸一夕而九運。揚流波之潢潢兮，體溶溶而東回。心怊悵以永思兮，意晻晻而日頽。白露紛㠯塗塗兮，秋風瀏㠯蕭蕭。身永流而不還兮，䰟長逝而常愁。
歎曰：譬彼流水，紛揚礚兮。波逢洶涌，濆滂沛兮。揄揚滌盪，漂流隕往，觸崟石兮。龍卬脟圈，繚戾宛轉，阻相薄兮。遭紛逢凶，蹇離尤兮。垂文揚采，遺將來兮。
靈懷其不吾知兮，靈懷其不吾聞。就靈懷之皇祖兮，愬靈懷之鬼神。靈懷曾不吾與兮，即聽夫人之諛辭。餘辭上參於天墬兮，旁引之於四時。指日月使延照兮，撫招摇㠯質正。立師曠俾端詞兮，命咎繇使竝聽。兆出名曰正則兮，卦發字曰靈均。餘幼既有此鴻節兮，長愈固而彌純。不從俗而詖行兮，直躬指而信志。不枉繩以追曲兮，屈情素以從事。端餘行其如玉兮，述皇輿之踵跡。羣阿容以晦光兮，皇輿覆以幽辟。輿中塗以回畔兮，駟馬驚而橫犇。執組者不能制兮，必折軛而摧轅。斷鑣銜㠯馳騖兮，暮去次而敢止。路蕩蕩其無人兮，遂不禦乎千里。
身衡陷而下沈兮，不可獲而復登。不顧身之卑賤兮，惜皇輿之不興。出國門而端指兮，冀壹寤而錫還。哀僕夫之坎毒兮，屢離憂而逢患。九年之中不吾反兮，思彭咸之水遊。惜師延之浮渚兮，赴汨羅之長流。遵江曲之逶移兮，觸石碕而衡遊。波澧澧而揚澆兮，順長瀨之濁流。淩黃沱而下低兮，思還流而復反。玄輿馳而竝集兮，身容與而日遠。櫂舟杭以橫濿兮，𣸓湘流而南極。立江界而長吟兮，愁哀哀而累息。情慌忽以忘歸兮，神浮遊以高厲。心蛩蛩而懷顧兮，䰟眷眷而獨逝。
歎曰：餘思舊邦，心依違兮。日暮黃昏，羌幽悲兮。去郢東遷，餘誰慕兮？讒夫黨旅，其㠯兹故兮。河水淫淫，情所願兮。顧瞻郢路，終不返兮。
惟鬱鬱之憂毒兮，志坎壈而不違。身憔悴而考旦兮，日黃昏而長悲。閔空宇之孤子兮，哀枯楊之寃鶵。孤雌吟於高墉兮，鳴鳩棲於桑榆。玄蝯失於潛林兮，獨偏弃而遠放。征夫勞於周行兮，處婦憤而長望。申誠信而罔違兮，情素潔於紐帛。光明齊於日月兮，文采燿於玉石。傷壓次而不發兮，思沈抑而不揚。芳懿懿而終敗兮，名靡散而不彰。
背玉門以犇騖兮，蹇離尤而乾詬。若龍逄之沈首兮，王子比乾之逢醢。念社稷之幾危兮，反爲讎而見怨。思國家之離沮兮，躳獲愆而結難。若青蠅之僞質兮，晉驪姬之反情。恐登階之逢殆兮，故退伏於末庭。孽臣之號咷兮，本朝蕪而不治。犯顏色而觸諫兮，反蒙辜而被疑。菀蘼蕪與菌若兮，漸藁本於洿瀆。淹芳芷於腐井兮，弃雞駭於筐簏。執棠谿㠯刜蓬兮，秉乾將以割肉。筐澤瀉㠯豹鞹兮，破荆和㠯繼築。時溷濁猶未清兮，世殽亂猶未察。欲容與㠯竢時兮，懼年歲之既晏。顧屈節以從流兮，心鞏鞏而不夷。寧浮沅而馳騁兮，下江湘㠯邅迴。
歎曰：山中檻檻，餘傷懷兮。征夫皇皇，其孰依兮。經營原野，杳冥冥兮。乘騏騁驥，舒吾情兮。歸骸舊邦，莫誰語兮。長辭遠逝，乘湘去兮。
志隱隱而鬱怫兮，愁獨哀而寃結。腸紛紜㠯繚轉兮，涕漸漸其若屑。情慨慨而長懷兮，信上皇而質正。合五嶽與八靈兮，訊九鬿與六神。指列宿以白情兮，訴五帝㠯置詞。北鬥爲我折中兮，太一爲餘聽之。雲服陰陽之正道兮，御後土之中和。佩蒼龍之蚴虬兮，帶隱虹之逶虵。曳彗星之皓旰兮，撫朱爵與鵕䴊。遊清靈之颯戾兮，服雲衣之披披。杖玉華與朱旗兮，垂明月之玄珠。舉霓旌之墆翳兮，建黃纁之總旄。躬純粹而罔愆兮，承皇考之妙儀。
惜往事之不合兮，橫汨羅而下濿。椉隆波而南渡兮，逐江湘之順流。赴陽侯之潢洋兮，下石瀨而登洲。陸魁堆以蔽視兮，雲冥冥而闇前。山峻高以無垠兮，遂曾閎而迫身。雪雰雰而薄木兮，雲霏霏而隕集。阜隘狹而幽險兮，石㠁嵯以翳日。悲故鄉而發忿兮，去餘邦之彌久。背龍門而入河兮，登大墳而望夏首。橫舟航而𣸓湘兮，耳聊啾而戃慌。波淫淫而周流兮，鴻溶溢而滔蕩。路曼曼其無端兮，周容容而無識。引日月以指極兮，少須臾而釋思。水波遠以冥冥兮，眇不睹其東西。順風波以南北兮，霧宵晦以紛紛。日杳杳以西頽兮，路長遠而窘迫。欲酌醴以娛憂兮，蹇騷騷而不釋。
歎曰：飄風蓬龍，埃坲坲兮。屮木摇落，時槁悴兮。遭傾遇禍，不可救兮。長吟永欷，涕究究兮。舒情敶詩，冀以自免兮。頽流下隕，身日遠兮。
覽屈氏之離騷兮，心哀哀而怫鬱。聲嗷嗷以寂寥兮，顧僕夫之憔悴。撥諂諛而匡邪兮，切淟涊之流俗。盪渨涹之姦咎兮，夷蠢蠢之溷濁。懷芬香而挾蕙兮，佩江蘺之婓婓。握申椒與杜若兮，冠浮雲之峨峨。登長陵而四望兮，覽芷圃之蠡蠡。遊蘭皋與蕙林兮，睨玉石之㠁嵯。揚精華以眩燿兮，芳鬱渥而純美。結桂樹之旖旎兮，紉荃蕙與辛夷。芳若兹而不御兮，捐林薄而菀死。
驅子僑之犇走兮，申徒狄之赴淵。若由夷之純美兮，介子推之隱山。晉申生之離殃兮，荆和氏之泣血。吳申胥之抉眼兮，王子比乾之橫廢。欲卑身而下體兮，心隱惻而不置。方圜殊而不合兮，鉤繩用而異態。欲竢時於須臾兮，日陰曀其將暮。時遲遲其日進兮，年忽忽而日度。妄周容而入世兮，內距閉而不開。竢時風之清激兮，愈氛霧其如塺。進雄鳩之耿耿兮，讒介介而蔽之。默順風以偃仰兮，尚由由而進之。心懭悢以寃結兮，情舛錯以曼憂。搴薜荔於山野兮，采撚支於中洲。望高丘而歎涕兮，悲吸吸而長懷。孰契契而委棟兮，日晻晻而下頽。
歎曰：江湘油油，長流汩兮。挑揄揚汰，盪迅疾兮。憂心展轉，愁怫鬱兮。寃結未舒，長隱忿兮。丁時逢殃，可奈何兮。勞心悁悁，涕滂沲兮。
悲餘心之悁悁兮，哀故邦之逢殃。辭九年而不復兮，獨煢煢而南行。思餘俗之流風兮，心紛錯而不受。遵壄莽以呼風兮，步從容於山廀。巡陸夷之曲衍兮，幽空虛以寂寞。倚石巖以流涕兮，憂憔悴而無樂。登巑岏以長企兮，望南郢而闚之。山脩遠其遼遼兮，塗漫漫其無時。聽玄鶴之晨鳴兮，于高岡之峨峨。獨憤積而哀娛兮，翔江洲而安歌。三鳥飛以自南兮，覽其志而欲北。願寄言於三鳥兮，去飄疾而不可得。
欲遷志而改操兮，心紛結其未離。外彷徨而遊覽兮，內惻隱而含哀。聊須臾以時忘兮，心漸漸其煩錯。願假簧以舒憂兮，志紆鬱其難釋。歎離騷以揚意兮，猶未殫於九章。長嘘吸以於悒兮，涕橫集而成行。傷明珠之赴泥兮，魚眼璣之堅藏。同駑驘與椉駔兮，雜斑駮與闒茸。葛藟虆於桂樹兮，鴟鴞集於木蘭。偓促談於廊廟兮，律魁放乎山間。惡虞氏之簫韶兮，好遺風之激楚。潛周鼎於江淮兮，爨土鬵於中宇。且人心之持舊兮，而不可保長。邅彼南道兮，征夫宵行。思念郢路兮，還顧睠睠。涕流交集兮，泣下漣漣。
歎曰：登山長望，中心悲兮。菀彼青青，泣如頽兮。留思北顧，涕漸漸兮。折銳摧矜，凝氾濫兮。念我煢煢，䰟誰求兮？僕夫慌悴，散若流兮。
昔皇考之嘉志兮，喜登能而亮賢。情純潔而罔薉兮，姿盛質而無愆。放佞人與諂諛兮，斥讒夫與便嬖。親忠正之悃誠兮，招貞良與明智。心溶溶其不可量兮，情澹澹其若淵。回邪辟而不能入兮，誠願藏而不可遷。逐下袟於後堂兮，迎宓妃於伊雒。刜讒賊於中廇兮，選呂管於榛薄。叢林之下無怨士兮，江河之畔無隱夫。三苗之徒以放逐兮，伊皋之倫以充廬。
今反表以爲裏兮，顛裳㠯爲衣。戚宋萬於兩楹兮，廢周邵於遐夷。却騏驥以轉運兮，騰驢驘以馳逐。蔡女黜而出帷兮，戎婦入而綵繡服。慶忌囚於阱室兮，陳不占戰而赴圍。破伯牙之號鍾兮，挾人箏而彈緯。藏瑉石於金匱兮，捐赤瑾於中庭。韓信蒙於介胄兮，行夫將而攻城。莞芎棄於澤洲兮，瓟瓥蠹於筐簏。麒麟奔於九皋兮，熊羆羣而逸囿。折芳枝與瓊華兮，樹枳棘與薪柴。掘荃蕙與射乾兮，耘藜藿與蘘荷。惜今世其何殊兮，遠近思而不同。或沈淪其無所達兮，或清激其無所通。哀餘生之不當兮，獨蒙毒而逢尤。雖謇謇以申志兮，君乖差而屏之。誠惜芳之菲菲兮，反以兹爲腐也。懷椒聊之蔎蔎兮，乃逢紛以罹詬也。
歎曰：嘉皇既殁，終不返兮。山中幽險，郢路遠兮。讒人諓諓，孰可愬兮。征夫罔極，誰可語兮。行唫累欷，聲喟喟兮。懷憂含戚，何侘傺兮。
冥冥深林兮，樹木鬱鬱。山參差以嶃巖兮，阜杳杳以蔽日。悲餘心之悁悁兮，目眇眇而遺泣。風騷屑以摇木兮，雲吸吸以湫戾。悲餘生之無歡兮，愁倥偬於山陸。旦徘徊於長阪兮，夕仿偟而獨宿。髮披披以鬤鬤兮，躬劬勞而瘏悴。䰟俇俇而南行兮，泣霑襟而濡袂。心嬋媛而無告兮，口噤閉而不言。違郢都之舊閭兮，回湘沅而遠遷。念餘邦之橫陷兮，宗鬼神之無次。閔先嗣之中絶兮，心惶惑而自悲。聊浮遊於山陿兮，步周流於江畔。臨深水而長嘯兮，且倘佯而氾觀。
興離騷之微文兮，冀靈修之壹悟。還餘車於南郢兮，復往軌於初古。道脩遠其難遷兮，傷餘心之不能已。背三五之典刑兮，絶洪範之辟紀。播規榘以背度兮，錯權衡而任意。操繩墨而放弃兮，傾容幸而侍側。甘棠枯於豐草兮，藜棘樹於中庭。西施斥於北宮兮，仳倠倚於彌楹。烏獲戚而驂乘兮，燕公操於馬圉。蒯聵登於清府兮，咎繇棄而在壄。蓋見兹以永歎兮，欲登階而狐疑。椉白水而高騖兮，因徙弛而長詞。
歎曰：倘佯壚阪，沼水深兮。容與漢渚，涕淫淫兮。鍾牙已死，誰爲聲兮？纖阿不御，焉舒情兮？曾哀悽欷，心離離兮。還顧高丘，泣如灑兮。
悲餘性之不可改兮，屢懲艾而不迻。服覺晧以殊俗兮，貌揭揭㠯巍巍。譬若王僑之乘雲兮，載赤霄而淩太清。欲與天地參壽兮，與日月而比榮。登崑崙而北首兮，悉靈圉而來謁。選鬼神於太陰兮，登閶闔於玄闕。回朕車俾西引兮，褰虹旗於玉門。馳六龍於三危兮，朝西靈於九濱。結餘軫於西山兮，橫飛谷以南征。絶都廣以直指兮，歷祝融於朱冥。枉玉衡於炎火兮，委兩館于咸唐。貫澒濛以東朅兮，維六龍於扶桑。
周流覽於四海兮，志升降以高馳。徵九神於回極兮，建虹采以招指。駕鸞鳳以上遊兮，從玄鶴與鷦明。孔鳥飛而送迎兮，騰羣鶴於瑤光。排帝宮與羅囿兮，升縣圃以眩滅。結瓊枝以雜佩兮，立長庚以繼日。淩驚靁以軼駭電兮，綴鬼谷於北辰。鞭風伯使先驅兮，囚靈玄於虞淵。遡高風以低佪兮，覽周流於朔方。就顓頊而敶詞兮，考玄冥於空桑。旋車逝於崇山兮，奏虞舜於蒼梧。𣸓楊舟於會稽兮，就申胥於五湖。見南郢之流風兮，殞餘躬於沅湘。望舊邦之黯黮兮，時溷濁其猶未央。懷蘭茝之芬芳兮，妬被離而折之。張絳帷以襜襜兮，風邑邑而蔽之。日暾暾其西舍兮，陽焱焱而復顧。聊假日以須臾兮，何騷騷而自故。
歎曰：譬彼蛟龍，乘雲浮兮。汎淫澒溶，紛若霧兮。潺湲轇轕，雷動電發，馺高舉兮。升虛淩冥，沛濁浮清，入帝宮兮。摇翹奮羽，馳風騁雨，遊無窮兮。', 'parsed', 'cnpt-chuci', '{"queue_id":"CN-TR-00398","source_record_id":"CN-CLASSIC-63-68-75-63-69-2d-31-36-2d-4e5d-6b4e-2d-5289-5411-2d-4e5d-6b4e","alias_record_ids":["CN-CLASSIC-63-68-75-63-69-2d-31-36-2d-4e5d-6b4e-2d-5289-5411-2d-4e5d-6b4e"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E4%B9%9D%E6%AD%8E","review_status":"needs-review","review_reasons":["classic-index-work","chuci"]}'),
    ('cnpreqin-5d5d2c304cffbc05', 0, '九思', NULL, NULL, NULL, '悲兮愁，哀兮憂。天生我兮當闇時，被諑譖兮虛獲尤。心煩憒兮意無聊，嚴載駕兮出戲遊。周八極兮歷九州，求軒轅兮索重華。世既卓兮遠眇眇，握佩玖兮中路躇。羨咎繇兮建典謨，懿風後兮受瑞圖。愍餘命兮遭六極，委玉質兮於泥塗。遽傽遑兮驅林澤，步屏營兮行丘阿。車軏折兮馬虺頽，憃悵立兮涕滂沲。思丁文兮聖明哲，哀平差兮迷謬愚。呂傅舉兮殷周興，忌𧯻專兮郢吳虛。仰長歎兮氣䭇結，悒殟絶兮咶復蘇。虎兕爭兮於廷中，豺狼鬭兮我之隅。雲霧會兮日冥晦，飄風起兮揚塵埃。走鬯罔兮乍東西，欲竄伏兮其焉如。念靈閨兮隩重深，願竭節兮隔無由。望舊邦兮路逶隨，憂心悄兮志勤劬。魂焭焭兮不遑寐，目眽眽兮寤終朝。
令尹兮謷謷，羣司兮譨譨。哀哉兮淈淈，上下兮同流。菽藟兮蔓衍，芳虈兮挫枯。朱紫兮雜亂，曾莫兮別諸。倚此兮巖穴，永思兮窈悠。嗟懷兮眩惑，用志兮不昭。將喪兮玉鬥，遺失兮鈕樞。我心兮煎熬，惟是兮用憂。進惡兮九旬，復顧兮彭務。擬斯兮二蹤，未知兮所投。謡吟兮中壄，上察兮璇璣。大火兮西睨，攝提兮運低。雷霆兮硠礚，雹霰兮霏霏。奔電兮光晃，涼風兮愴悽。鳥獸兮驚駭，相從兮宿棲。鴛鴦兮噰噰，狐貍兮徾徾。哀吾兮介特，獨處兮罔依。螻蛄兮鳴東，蟊䘁兮號西。蛓緣兮我裳，蠋入兮我懷。蟲豸兮夾餘，惆悵兮自悲。佇立兮忉怛，心結縎兮折摧。
周徘徊兮漢渚，求水神兮靈女。嗟此國兮無良，媒女詘兮謰謱。鴳雀列兮譁讙，鴝鵒鳴兮聒餘。抱昭華兮寶璋，欲衒鬻兮莫取。言旋邁兮北徂，叫我友兮配耦。日陰曀兮未光，闃𣆺窕兮靡睹。紛載驅兮高馳，將諮詢兮皇羲。遵河皋兮周流，路變易兮時乖。濿滄海兮東遊，沐盥浴兮天池。訪太昊兮道要，雲靡貴兮仁義。志欣樂兮反征，就周文兮邠岐。秉玉英兮結誓，日欲暮兮心悲。惟天祿兮不再，背我信兮自違。踰隴堆兮渡漠，過桂車兮合黎。赴崑山兮馽騄，從邛遨兮棲遲。吮玉液兮止渴，齧芝華兮療飢。居嵺廓兮尠疇，遠梁昌兮幾迷。望江漢兮濩渃，心緊絭兮傷懷。時昢昢兮旦旦，塵莫莫兮未晞。憂不暇兮寢食，吒增歎兮如雷。
哀世兮睩睩，諓諓兮嗌喔。衆多兮阿媚，骫靡兮成俗。貪枉兮黨比，貞良兮焭獨。鵠竄兮枳棘，鵜集兮帷幄。蘮蕠兮青䓗，槀本兮萎落。覩斯兮僞惑，心爲兮隔錯。逡巡兮圃藪，率彼兮畛陌。川谷兮淵淵，山峊兮峉峉。叢林兮崯崯，株榛兮嶽嶽。霜雪兮漼溰，冰凍兮洛澤。東西兮南北，罔所兮歸薄。庇廕兮枯樹，匍匐兮巖石，踡跼兮寒局數。獨處兮志不申，年齒盡兮命迫促，魁壘擠摧兮常困辱。含憂強老兮愁不樂，鬚髮薴顇兮顠鬢白，思靈澤兮一膏沐。懷蘭英兮把瓊若，待天明兮立躑躅。雲蒙蒙兮電儵爍，孤雌驚兮鳴呴呴。思怫鬱兮肝切剝，忿悁悒兮孰訴告。
悼屈子兮遭厄，沈玉躬兮湘汨。何楚國兮難化，迄于今兮不易。士莫志兮羔裘，競佞諛兮讒鬩。指正義兮爲曲，訿玉璧兮爲石。殦鵰遊兮華屋，鵕䴊棲兮柴蔟。起奮迅兮奔走，違羣小兮謑訽。載青雲兮上昇，適昭明兮所處。躡天衢兮長驅，踵九陽兮戲蕩。越雲漢兮南濟，秣餘馬兮河鼓。雲霓紛兮晻翳，參辰回兮顛倒。逢流星兮問路，顧我指兮從左。俓娵觜兮直馳，御者迷兮失軌。遂踼達兮邪造，與日月兮殊道。志閼絶兮安如，哀所求兮不耦。攀天階兮下視，見鄢郢兮舊宇。意逍遥兮欲歸，衆穢盛兮杳杳。思哽饐兮詰詘，涕流瀾兮如雨。
嗟嗟兮悲夫，殽亂兮紛挐。茅絲兮同綜，冠屨兮共絇。督萬兮侍宴，周邵兮負蒭。白龍兮見䠶，靈龜兮執拘。仲尼兮困厄，鄒衍兮幽囚。伊餘兮念兹，奔遁兮隱居。將升兮高山，上有兮猴猿。欲入兮深谷，下有兮虺蛇。左見兮鳴鵙，右睹兮呼梟。惶悸兮失氣，踊躍兮距跳。便旋兮中原，仰天兮增歎。菅蒯兮壄莽，雚葦兮仟眠。鹿蹊兮𨇰𨇰，貒貉兮蟫蟫。鸇鷂兮軒軒，鶉䳺兮甄甄。哀我兮寡獨，靡有兮齊倫。意欲兮沈吟，迫日兮黃昏。玄鶴兮高飛，曾逝兮青冥。鶬鶊兮喈喈，山鵲兮嚶嚶。鴻鸕兮振翅，歸鴈兮于征。吾志兮覺悟，懷我兮聖京。垂屣兮將起，跓竢兮碩明。
惟昊天兮昭靈，陽氣發兮清明。風習習兮龢煖，百草萌兮華榮。堇荼茂兮扶疏，蘅芷彫兮瑩嫇。愍貞良兮遇害，將夭折兮碎糜。時混混兮澆饡，哀當世兮莫知。覽往昔兮俊彥，亦詘辱兮係纍。管束縛兮桎梏，百𧵍易兮傅賣。遭桓繆兮識舉，才德用兮列施。且從容兮自慰，玩琴書兮遊戲。迫中國兮迮陿，吾欲之兮九夷。超五嶺兮嵯峨，觀浮石兮崔嵬。陟丹山兮炎野，屯餘車兮黃支。就祝融兮稽疑，嘉己行兮無爲。乃回朅兮北逝，遇神孈兮宴娭。欲靜居兮自娛，心愁慼兮不能。放餘轡兮策駟，忽飇騰兮浮雲。蹠飛杭兮越海，從安期兮蓬萊。緣天梯兮北上，登太一兮玉臺。使素女兮鼓簧，乘戈龢兮謳謡。聲噭誂兮清和，音晏衍兮要媱。咸欣欣兮酣樂，餘眷眷兮獨悲。顧章華兮太息，志戀戀兮依依。
旻天兮清涼，玄氣兮高朗。北風兮潦洌，草木兮蒼唐。𧉅蚗兮噍噍，蝍蛆兮穰穰。歲忽忽兮惟暮，餘感時兮悽愴。傷俗兮泥濁，矇蔽兮不章。寶彼兮沙礫，捐此兮夜光。椒瑛兮湼汙，葈耳兮充房。攝衣兮緩帶，操我兮墨陽。陞車兮命僕，將馳兮四荒。下堂兮見蠆，出門兮觸𧒒。巷有兮蚰蜓，邑多兮螳螂。睹斯兮嫉賊，心爲兮切傷。俛念兮子胥，仰憐兮比乾。投劒兮脫冕，龍屈兮蜿蟤。潛藏兮山澤，匍匐兮叢攢。窺見兮溪澗，流水兮沄沄。黿鼉兮欣欣，鱣鮎兮延延。群行兮上下，駢羅兮列陳。自恨兮無友，特處兮煢煢。冬夜兮陶陶，雨雪兮冥冥。神光兮熲熲，鬼火兮熒熒。修德兮困控，愁不聊兮遑生。憂紆兮鬱鬱，惡所兮寫情。
陟玉巒兮逍遥，覽高岡兮嶢嶢。桂樹列兮紛敷，吐紫華兮布條。實孔鸞兮所居，今其集兮惟鴞。烏鵲驚兮啞啞，餘顧瞻兮怊怊。彼日月兮闇昧，障覆天兮祲氛。伊我後兮不聦，焉陳誠兮效忠。攄羽翮兮超俗，遊陶遨兮養神。乘六蛟兮蜿蟬，遂馳騁兮陞雲。揚彗光兮爲旗，秉電策兮爲鞭。朝晨發兮鄢郢，食時至兮增泉。繞曲阿兮北次，造我車兮南端。謁玄黃兮納贄，崇忠貞兮彌堅。歷九宮兮徧觀，睹祕藏兮寶珍。就傅說兮騎龍，與織女兮合婚。舉天罼兮掩邪，彀天弧兮䠶姦。隨真人兮翱翔，食元氣兮長存。望太微兮穆穆，睨三階兮炳分。相輔政兮成化，建烈業兮垂勳。目瞥瞥兮西沒，道遐迥兮阻歎。志稸積兮未通，悵敞罔兮自憐。
亂曰：天庭明兮雲霓藏，三光朗兮鏡萬方。斥𧌨蜴兮進龜龍，策謀從兮翼機衡。配稷契兮恢唐功，嗟英俊兮未爲雙。', 'parsed', 'cnpt-chuci', '{"queue_id":"CN-TR-00399","source_record_id":"CN-CLASSIC-63-68-75-63-69-2d-31-37-2d-4e5d-601d-2d-738b-9038-2d-4e5d-601d","alias_record_ids":["CN-CLASSIC-63-68-75-63-69-2d-31-37-2d-4e5d-601d-2d-738b-9038-2d-4e5d-601d"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E4%B9%9D%E6%80%9D","review_status":"needs-review","review_reasons":["classic-index-work","chuci"]}'),
    ('cnpreqin-d9cfb1495fcebc18', 0, '離騷', NULL, NULL, NULL, '帝高陽之苗裔兮，朕皇考曰伯庸。
攝提貞于孟陬兮，惟庚寅吾以降。
皇覽揆餘初度兮，肇錫餘以嘉名。
名餘曰正則兮，字餘曰靈均。
紛吾既有此內美兮，又重之以脩能。
扈江離與辟芷兮，紐秋蘭以為佩。
汩餘若將不及兮，恐年歲之不吾與。
朝搴阰之木蘭兮，夕攬洲之宿莽。
日月忽其不淹兮，春與秋其代序。
惟草木之零落兮，恐美人之遲暮。
不撫壯而棄穢兮，何不改乎此度？
乘騏驥以馳騁兮，來吾道夫先路。
昔三後之純粹兮，固衆芳之所在。
雜申椒與菌桂兮，豈維紐
初既與餘成言兮，後悔遁而有他。
餘既不難離別兮，傷靈脩之數化。
餘既滋蘭之九畹兮，又樹蕙之百畝。
畦留夷與揭車兮，雜杜衡與芳芷。
冀枝葉之峻茂兮，願竢時乎吾將刈。
雖萎絶其亦何傷兮，哀衆芳之蕪穢。
衆皆競進以貪婪兮，憑不猒乎求索。
羌內恕己以量人兮，各興心而嫉妒。
忽馳騖以追逐兮，非餘心之所急。
老冉冉其將至兮，恐脩名之不立。
朝飲木蘭之墜露兮，夕餐秋菊之落英。
苟餘情其信姱以練要兮，長顑頷亦何傷？
攬木根以結茝兮，貫薜荔之落蕊。
矯菌桂以紉蕙兮，索胡繩之纚纚。
謇吾法夫前脩兮，非時俗之所服。
雖不周於今之人兮，願依彭咸之遺則。
長太息以掩涕兮，哀民生之多艱。
餘雖好脩姱以鞿羈兮，謇朝誶而夕替。
既替餘以蕙纕兮，又申之㠯攬茝。
亦餘心之所善兮，雖九死其猶未悔。
怨靈脩之浩蕩兮，終不察夫民而固然。
何方圜之能周兮，夫孰異道而相安。
屈心而抑志兮，忍尤而攘詬。
伏清白以死直兮，固前聖之所厚。
悔相道之不察兮，延佇乎吾將反。
回朕車以復路兮，及行迷之未遠。
步餘馬於蘭臯兮，馳椒丘且焉止息。
進不入以離尤兮，退將復脩吾初服。
製芰荷以為衣兮，集芙蓉以為裳。
不吾知其亦已兮，苟餘情其信芳。
高餘冠之岌岌兮，長餘佩之陸離。
芳與澤其雜糅兮，唯昭質其猶未虧。
忽反顧以遊目兮，將往觀乎四荒。
佩繽紛其繁飾兮，芳菲菲其彌章。
民繩墨而不頗。
皇天無私阿兮，覽民以相羊。
前望舒使先驅兮，後飛廉使奔屬。
鸞皇為餘先戒兮，雷師告餘以未具。
吾令鳳鳥飛騰兮，繼之以日夜。
飄風屯其相離兮，帥雲霓而來御。
紛緫緫其離合兮，斑陸離其上下。
吾令帝閽開關兮，倚閶闔而望予。
時曖曖其將罷兮，結幽蘭而延佇。
世溷濁而不分兮，好蔽美而嫉妒。
朝吾將濟於白水兮，登閬風而緤馬。
忽反顧以流涕兮，哀高丘之無女。
溘吾遊此春宮兮，折瓊枝以繼佩。
及榮華之未落兮，相下女之可詒。
吾令豐隆椉雲兮，求宓妃之所在。
解佩纕以結言兮，吾令蹇脩以為理。
紛緫緫其離合兮，忽緯繣其難遷。
夕歸次於窮石兮，朝濯髮乎洧盤。
保厥美以驕傲兮，日康娛以淫遊。
雖信美而無禮兮，來違棄而改求。
覽相觀於四極兮，周流乎天餘乃下。
望瑤臺之偃蹇兮，見有娀之佚女。
吾令鴆為媒兮，鴆告餘以不好。
雄鳩之鳴逝兮，餘猶惡其佻巧。
心猶豫而狐疑兮，欲自適而不可。
鳳皇既受詒兮，恐高辛之先我。
欲遠集而無所止兮，聊浮遊以逍遙。
及少康之未家兮，留有虞之二姚。
理弱而媒拙兮，恐導言之不固。
世溷濁而嫉賢兮，好蔽美而稱惡。
閨中既以邃遠兮，哲王又不寤。
懷朕情而不發兮，餘焉能忍與此終古。
索藑茅以筳篿兮，命靈氛為餘占之。
曰：兩美其必合兮，孰信脩而慕之？
思九州之博大兮，豈唯是其有女？
曰：勉遠逝而無狐疑兮，孰求美而釋女？
何所獨無芳草兮，爾何懷乎故宇？
世降以上下兮，求榘矱之所同。
湯禹嚴而求合兮，摯咎繇而能調。
苟中情其好脩兮，何必用夫行媒。
說操築於傳巖兮，武丁用而不疑。
呂望之鼓刀兮，遭周文而得舉。
甯戚之謳歌兮，齊桓聞以該輔。
及年歲之未宴兮，時亦猶其未央。
恐鵜鴃之先鳴兮，使百草為之不芳。
何瓊佩之偃蹇兮，衆薆然而蔽之。
惟此黨人之不諒兮，恐嫉妒而折之。
時繽紛其變易兮，又何可以淹留。
蘭芷變而不芳兮，荃蕙化而為茅。
何昔日之芳草兮，今直為此蕭艾也。
豈其有他故兮，莫好脩之害也。
餘以蘭為可恃兮，羌無實而容長。
委厥美以從俗兮，苟得列乎衆芳。
椒專佞以慢慆兮，樧又欲充夫佩幃。
既乾進而務入兮，又何芳之能祗。
固時俗之流從兮，又孰能無變化。
覽椒蘭其若玆兮，又況揭車與江離。
惟玆佩之可貴兮，委厥美而歷玆。
芳菲菲而難虧兮，芬至今猶未沬。
和調度以自娛兮，聊浮遊而求女。
及餘飾之方壯兮，周流觀乎上下。
靈氛既告餘以吉占兮，歷吉日乎吾將行。
折瓊枝以為羞兮，精瓊爢以為粻。
為餘駕飛龍兮，雜瑤象以為車。
何離心之可同兮，吾將遠逝以自疏。
邅吾道夫崑崙兮，路脩遠以周流。
揚雲霓之晻藹兮，鳴玉鸞之啾啾。
朝發軔於天津兮，夕餘至乎西極。
鳳皇翼其承旂兮，高翱翔之翼翼。
忽吾行此流沙兮，遵赤水而容與。
麾蛟龍使梁津兮，詔西皇使涉予。
路脩遠以多艱兮，騰衆車使徑待。
路不周以左轉兮，指西海以為期。
屯餘車其千乘兮，齊玉軑而並馳。
駕八龍之婉婉兮，載雲旗之委蛇。
抑志而弭節兮，神高馳之邈邈。
奏《九歌》而舞《韶》兮，聊假日以媮樂。
陟陞皇之赫戲兮，忽臨睨夫舊鄉。
僕夫悲餘馬懷兮，蜷局顧而不行。
亂曰：已矣哉，
國無人莫我知兮，又何懷乎故都？
既莫足與為美政兮，吾將從彭咸之所居。', 'parsed', 'cnpt-chuci', '{"queue_id":"CN-TR-00400","source_record_id":"CN-CLASSIC-63-68-75-63-69-2d-31-2d-96e2-9a37-2d-5c48-539f-2d-96e2-9a37","alias_record_ids":["CN-CLASSIC-63-68-75-63-69-2d-31-2d-96e2-9a37-2d-5c48-539f-2d-96e2-9a37"],"batch":"pre-tang-classic-index","source_url":"https://zh.wikisource.org/wiki/%E9%9B%A2%E9%A8%B7","review_status":"needs-review","review_reasons":["classic-index-work","chuci"]}')
)
INSERT INTO poems (
  poet_id, poem_no, volume, title_zh, title_ko, category, meter, body_zh,
  is_notable, status, quality, review_memo
)
SELECT
  p.id,
  COALESCE(existing_poem_count.max_poem_no, 0)
    + row_number() OVER (PARTITION BY p.id ORDER BY ip.title_zh, ip.body_zh)::integer,
  ip.volume::integer, ip.title_zh, ip.title_ko, ip.category, ip.meter::integer, ip.body_zh,
  TRUE, ip.status, ip.quality, ip.review_memo
FROM input_poems ip
JOIN poets p ON p.title_id = ip.poet_slug
LEFT JOIN LATERAL (
  SELECT max(poem_no) AS max_poem_no
  FROM poems
  WHERE poet_id = p.id
) existing_poem_count ON TRUE
WHERE NOT EXISTS (
  SELECT 1
  FROM poems existing
  WHERE existing.poet_id = p.id
    AND existing.title_zh = ip.title_zh
    AND existing.body_zh = ip.body_zh
);

UPDATE poets p
SET poem_count = sub.cnt
FROM (
  SELECT poet_id, count(*)::integer AS cnt
  FROM poems
  WHERE poet_id IN (SELECT id FROM poets WHERE title_id IN ('cnpreqin-3fcc3c660d5a7a4d', 'cnpreqin-d9cfb1495fcebc18', 'cnpreqin-7ffd49878d637ea2', 'cnpreqin-5d5d2c304cffbc05'))
  GROUP BY poet_id
) sub
WHERE p.id = sub.poet_id;

-- Review counts before COMMIT when applying manually:
SELECT quality, status, count(*) FROM poems WHERE quality IN ('cnpt-shijing', 'cnpt-chuci') GROUP BY quality, status ORDER BY quality, status;
SELECT p.era_period, count(pm.id) FROM poets p JOIN poems pm ON pm.poet_id = p.id WHERE p.title_id IN ('cnpreqin-3fcc3c660d5a7a4d', 'cnpreqin-d9cfb1495fcebc18', 'cnpreqin-7ffd49878d637ea2', 'cnpreqin-5d5d2c304cffbc05') GROUP BY p.era_period ORDER BY p.era_period;

ROLLBACK;
-- COMMIT;
